import com.gcancino.levelingup.presentation.auth.signIn.SignInScreen
import com.gcancino.levelingup.presentation.initialization.InitScreen
import com.gcancino.levelingup.presentation.onboarding.OnboardingScreen
import com.gcancino.levelingup.presentation.player.dailyTasks.EveningFlowScreen
import com.gcancino.levelingup.presentation.player.dailyTasks.MorningFlowScreen
import com.gcancino.levelingup.presentation.player.dailyTasks.TasksScreen
import com.gcancino.levelingup.presentation.player.dashboard.DashboardScreen
import com.gcancino.levelingup.presentation.player.identity.IdentitySetupScreen
import com.gcancino.levelingup.presentation.player.identity.IdentityWallScreen
import com.gcancino.levelingup.presentation.player.identity.StandardsScreen
import com.gcancino.levelingup.presentation.player.profile.ProfileScreen
import com.gcancino.levelingup.presentation.player.session.SessionPlayerScreen
import com.gcancino.levelingup.ui.theme.BackgroundColor
import com.gcancino.levelingup.ui.components.quests.QuestStartedScreen
import java.time.LocalDate
import java.time.ZoneId
@ExperimentalAnimationApi
@ExperimentalMaterial3Api
@ExperimentalFoundationApi
@Composable
fun Navigation() {
    val navController: NavHostController = rememberNavController()
    NavHost(
        navController = navController,
        startDestination = "initScreen",
        modifier = Modifier
            .fillMaxSize()
            .background(BackgroundColor)
    ) {
        composable("initScreen") {
            InitScreen(
                viewModel = hiltViewModel(),
                onSignedIn = {
                    navController.navigate("dashboard") {
                        popUpTo("initScreen") { inclusive = true }
                    }
                },
                onSignInError = {
                    navController.navigate("dashboard") {
                        popUpTo("initScreen") { inclusive = true }
                    }
                },
                onNeedsOnboarding = {
                    navController.navigate("onboarding") {
                        popUpTo("initScreen") { inclusive = true }
                    }
                }
            )
        }
        composable("signIn") {
            SignInScreen(
                viewModel = hiltViewModel(),
                onSignedIn = {
                    navController.navigate("dashboard") {
                        popUpTo("signIn") { inclusive = true }
                    }
                },
                onSignInError = {  },
                onGoToSignUp = {
                    navController.navigate("signUp") {
                        popUpTo("initScreen") { inclusive = true }
                    }
                }
            )
        }
        composable("onboarding") {
            OnboardingScreen(
                viewModel    = hiltViewModel(),
                onCompleted  = {
                    navController.navigate("dashboard") {
                        popUpTo("onboarding") { inclusive = true }
                    }
                },
                onDismiss = {
                    navController.navigate("dashboard")
                }
            )
        }
        composable("dashboard") {
            DashboardScreen(
                viewModel = hiltViewModel(),
                bodyCompositionBottomSheetViewModel = hiltViewModel(),
                notificationViewModel = hiltViewModel(),
                tasksViewModel = hiltViewModel(),
                activeQuestViewModel = hiltViewModel(),
                identityViewModel = hiltViewModel(),
                onStartSession = { date: LocalDate ->
                    val timestamp = date
                        .atStartOfDay(ZoneId.systemDefault())
                        .toInstant()
                        .toEpochMilli()
                    navController.navigate("sessionPlayer/$timestamp")
                },
                onViewStandards = { navController.navigate("standards") },
                onSetupIdentity = { navController.navigate("identitySetup") },
                onProfileClick = { navController.navigate("profile") },
                onStartMorningFlow = { navController.navigate("morningFlow") },
                onStartEveningFlow = { navController.navigate("eveningFlow") }
            )
        }
        composable("profile") {
            ProfileScreen(
                viewModel = hiltViewModel(),
                onNavigateBack = { navController.popBackStack() },
                onNavigateToIdentityWall = { navController.navigate("identity/wall") },
                onSignOut = {
                    navController.navigate("signIn") {
                        popUpTo(0) { inclusive = true }
                    }
                }
            )
        }
        composable("questStarted") {
            QuestStartedScreen(
                viewModel      = hiltViewModel(),
                onNavigateBack = { navController.popBackStack() }
            )
        }
        composable("standards") {
            StandardsScreen(onNavigateBack = { navController.popBackStack() })
        }
        composable("identity/wall") {
            IdentityWallScreen(
                viewModel      = hiltViewModel(),
                onNavigateBack = { navController.popBackStack() }
            )
        }
        composable("identitySetup") {
            IdentitySetupScreen(
                viewModel   = hiltViewModel(),
                onCompleted = { navController.popBackStack() }
            )
        }
        composable(
            route     = "sessionPlayer/{date}",
            arguments = listOf(navArgument("date") { type = NavType.LongType })
        ) {
            SessionPlayerScreen(
                viewModel      = hiltViewModel(),
                onNavigateBack = { navController.popBackStack() }
            )
        }
        composable("morningFlow") {
            MorningFlowScreen(onCompleted = { navController.popBackStack() })
        }
        composable("eveningFlow") {
            EveningFlowScreen(onCompleted = { navController.popBackStack() })
        }
        composable("tasks") {
            TasksScreen(onNavigateBack = { navController.popBackStack() })
        }
    }
}



package com.gcancino.levelingup.core
import android.content.Context
import android.content.Intent
import android.os.Bundle
import android.os.Handler
import android.os.Looper
import android.speech.RecognitionListener
import android.speech.RecognizerIntent
import android.speech.SpeechRecognizer
import com.gcancino.levelingup.domain.models.VoiceToTextParserState
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.flow.update
class OnlineVoiceParser(
    private val context: Context
) : RecognitionListener, IVoiceToTextParser {
    private val _state = MutableStateFlow(VoiceToTextParserState())
    override val state = _state.asStateFlow()
    private val recognizer: SpeechRecognizer? = SpeechRecognizer.createSpeechRecognizer(context)
    private var currentLanguageCode = "en-US"
    private var isContinuousListening = false
    private var onCommandReceived: ((String) -> Unit)? = null
    override fun startContinuousListening(
        languageCode: String,
        onCommand: (String) -> Unit
    ) {
        currentLanguageCode = languageCode
        onCommandReceived = onCommand
        isContinuousListening = true
        startListening()
    }
    override fun stopContinuousListening() {
        isContinuousListening = false
        onCommandReceived = null
        stopListening()
    }
    private fun startListening() {
        _state.update { VoiceToTextParserState() }
        if (!SpeechRecognizer.isRecognitionAvailable(context)) {
            _state.update {
                it.copy(error = "Speech recognition not available")
            }
            return
        }
        val intent = Intent(RecognizerIntent.ACTION_RECOGNIZE_SPEECH).apply {
            putExtra(RecognizerIntent.EXTRA_LANGUAGE_MODEL, RecognizerIntent.LANGUAGE_MODEL_FREE_FORM)
            putExtra(RecognizerIntent.EXTRA_LANGUAGE, currentLanguageCode)
            putExtra(RecognizerIntent.EXTRA_PARTIAL_RESULTS, true)
            putExtra(RecognizerIntent.EXTRA_MAX_RESULTS, 1)
        }
        recognizer?.setRecognitionListener(this)
        recognizer?.startListening(intent)
        _state.update {
            it.copy(isSpeaking = true)
        }
    }
    fun stopListening() {
        _state.update {
            it.copy(isSpeaking = false)
        }
        recognizer?.stopListening()
    }
    private fun parseCommand(spokenText: String): String? {
        val text = spokenText.lowercase().trim()
        return when {
            text.contains("start") -> "START"
            text.contains("stop") -> "STOP"
            text.contains("pause") -> "PAUSE"
            text.contains("resume") -> "RESUME"
            else -> null
        }
    }
    private fun restartListening() {
        if (isContinuousListening) {
            Handler(Looper.getMainLooper()).postDelayed({
                if (isContinuousListening) {
                    startListening()
                }
            }, 500)
        }
    }
    override fun onBeginningOfSpeech() = Unit
    override fun onBufferReceived(p0: ByteArray?) = Unit
    override fun onEndOfSpeech() {
        _state.update {
            it.copy(isSpeaking = false)
        }
    }
    override fun onError(error: Int) {
        if (error == SpeechRecognizer.ERROR_CLIENT) {
            return
        }
        _state.update {
            it.copy(
                error = when (error) {
                    SpeechRecognizer.ERROR_NETWORK_TIMEOUT -> "Network timeout"
                    SpeechRecognizer.ERROR_NETWORK -> "Network error"
                    SpeechRecognizer.ERROR_AUDIO -> "Audio error"
                    SpeechRecognizer.ERROR_SERVER -> "Server error"
                    SpeechRecognizer.ERROR_SPEECH_TIMEOUT -> "Speech timeout"
                    SpeechRecognizer.ERROR_NO_MATCH -> "No speech detected"
                    SpeechRecognizer.ERROR_RECOGNIZER_BUSY -> "Recognizer busy"
                    else -> "Recognition error: $error"
                },
                isSpeaking = false
            )
        }
        if (isContinuousListening && error in listOf(
                SpeechRecognizer.ERROR_SPEECH_TIMEOUT,
                SpeechRecognizer.ERROR_NO_MATCH
            )) {
            restartListening()
        }
    }
    override fun onEvent(p0: Int, p1: Bundle?) = Unit
    override fun onPartialResults(results: Bundle?) {
        results?.getStringArrayList(SpeechRecognizer.RESULTS_RECOGNITION)
            ?.getOrNull(0)
            ?.let { partialText ->
                _state.update {
                    it.copy(partialText = partialText)
                }
                parseCommand(partialText)?.let { command ->
                    onCommandReceived?.invoke(command)
                }
            }
    }
    override fun onReadyForSpeech(p0: Bundle?) {
        _state.update {
            it.copy(error = null)
        }
    }
    override fun onResults(results: Bundle?) {
        results?.getStringArrayList(SpeechRecognizer.RESULTS_RECOGNITION)
            ?.getOrNull(0)
            ?.let { spokenText ->
                _state.update {
                    it.copy(
                        spokenText = spokenText,
                        lastCommand = parseCommand(spokenText)
                    )
                }
                parseCommand(spokenText)?.let { command ->
                    onCommandReceived?.invoke(command)
                }
                restartListening()
            }
    }
    override fun onRmsChanged(rmsdB: Float) {
        _state.update {
            it.copy(voiceLevel = rmsdB)
        }
    }
    override fun cleanup() {
        isContinuousListening = false
        recognizer?.destroy()
    }
}



package com.gcancino.levelingup.core
sealed class Resource(
    val data: T? = null,
    val message: String? = null,
    val exception: Exception? = null
) {
    class Success(data: T) : Resource(data)
    class Error(message: String, data: T? = null, exception: Exception? = null) : Resource(data, message, exception)
    class Loading(data: T? = null) : Resource(data)
}



package com.gcancino.levelingup.core
sealed class SyncState {
    object Idle : SyncState()
    object Syncing : SyncState()
    object Success : SyncState()
    data class Error(val message: String) : SyncState()
}



package com.gcancino.levelingup.data.local.database.converters
import androidx.room.TypeConverter
import com.gcancino.levelingup.domain.models.dailyTasks.TaskPriority
import com.google.gson.Gson
import java.util.Date
class CommonConverters {
    @TypeConverter
    fun fromDate(date: Date?): Long? = date?.time
    @TypeConverter
    fun toDate(timestamp: Long?): Date? = timestamp?.let { Date(it) }
    @TypeConverter
    fun fromStringList(value: List): String = Gson().toJson(value)
    @TypeConverter
    fun toStringList(value: String): List = Gson().fromJson(value, Array::class.java).toList()
    @TypeConverter
    fun fromTaskPriority(priority: TaskPriority): String = priority.name
    @TypeConverter
    fun toTaskPriority(name: String): TaskPriority = try {
        TaskPriority.valueOf(name)
    } catch (e: Exception) {
        TaskPriority.LOW
    }
}



