package com.gcancino.levelingup.data.local.database.converters
import androidx.room.TypeConverter
import com.gcancino.levelingup.domain.models.player.Genders
import com.gcancino.levelingup.domain.models.player.Improvement
import com.google.gson.Gson
import com.google.gson.reflect.TypeToken
class PlayerConverters {
    private val gson = Gson()
    @TypeConverter
    fun fromImprovements(improvements: List?): String? = gson.toJson(improvements)
    @TypeConverter
    fun toImprovements(json: String?): List? {
        val list = object : TypeToken<List>() {}.type
        return gson.fromJson(json, list)
    }
    @TypeConverter
    fun fromStringList(value: List?): String? {
        return value?.let { gson.toJson(it) }
    }
    @TypeConverter
    fun toStringList(value: String?): List? {
        return value?.let {
            val listType = object : TypeToken<List>() {}.type
            gson.fromJson(it, listType)
        }
    }
    @TypeConverter
    fun fromGender(gender: Genders?): String? = gender?.name
    @TypeConverter
    fun toGender(gender: String?): Genders? = gender?.let {
        try {
            Genders.valueOf(it)
        } catch (e: Exception) {
            null
        }
    }
}



