)
@Entity(
    tableName = "exercises",
    foreignKeys = [ForeignKey(
        entity = ExerciseBlockEntity::class,
        parentColumns = ["id"],
        childColumns = ["blockId"],
        onDelete = ForeignKey.CASCADE
    )],
    indices = [Index(value = ["blockId"])]
)
