import java.util.Date
fun Player.toEntity(): PlayerEntity {
    return PlayerEntity(
        uid = this.uid,
        displayName = this.displayName,
        email = this.email,
        photoURL = this.photoURL,
        birthDate = this.birthDate,
        age = this.age,
        height = this.height,
        gender = this.gender,
        improvements = this.improvements ?: emptyList(),
        lastSync = Date(),
        needsSync = false
    )
}
fun PlayerEntity.toDomain(): Player {
    return Player(
        uid = this.uid,
        displayName = this.displayName,
        email = this.email,
        photoURL = this.photoURL,
        birthDate = this.birthDate,
        age = this.age,
        height = this.height,
        gender = this.gender,
        improvements = this.improvements
    )
}
fun PlayerProgressEntity.toDomain(): Progress {
    return Progress(
        uid = this.uid,
        coins = this.coins,
        exp = this.exp,
        level = this.level,
        availablePoints = this.availablePoints,
        currentCategory = CategoryType.fromString(this.currentCategory)
    )
}
fun Progress.toEntity(): PlayerProgressEntity {
    return PlayerProgressEntity(
        uid = this.uid,
        coins = this.coins,
        exp = this.exp,
        level = this.level,
        availablePoints = this.availablePoints,
        currentCategory = this.currentCategory.name
    )
}
fun PlayerAttributesEntity.toDomain(): Attributes {
    return Attributes(
        uid = this.uid,
        strength = this.strength,
        endurance = this.endurance,
        intelligence = this.intelligence,
        mobility = this.mobility,
        health = this.health,
        finance = this.finance
    )
}
fun Attributes.toEntity() : PlayerAttributesEntity {
    return PlayerAttributesEntity(
        uid = this.uid,
        strength = this.strength,
        endurance = this.endurance,
        intelligence = this.intelligence,
        mobility = this.mobility,
        health = this.health,
        finance = this.finance
    )
}
fun PlayerStreakEntity.toDomain(): Streak {
    return Streak(
        uid = this.uid,
        currentStreak = this.currentStreak,
        longestStreak = this.longestStreak,
        lastStreakUpdate = this.lastStreakUpdate?.let { Date(it) } ?: Date()
    )
}
fun Streak.toEntity(): PlayerStreakEntity {
    return PlayerStreakEntity(
        uid = this.uid,
        currentStreak = this.currentStreak,
        longestStreak = this.longestStreak,
        lastStreakUpdate = this.lastStreakUpdate?.time
    )
}
fun PlayerEntity.isFresh(maxAgeMinutes: Long = 480): Boolean {
    val currentTime = System.currentTimeMillis()
    val lastSyncTime = lastSync.time
    val ageInMinutes = (currentTime - lastSyncTime) / (1000 * 60)
    return ageInMinutes <= maxAgeMinutes
}



package com.gcancino.levelingup.data.mappers
import com.gcancino.levelingup.data.local.database.entities.QuestEntity
import com.gcancino.levelingup.domain.models.QuestDetails
import com.gcancino.levelingup.domain.models.QuestRewards
import com.gcancino.levelingup.domain.models.QuestStatus
import com.gcancino.levelingup.domain.models.QuestStreak
import com.gcancino.levelingup.domain.models.Quests
import com.gcancino.levelingup.domain.models.player.Improvement
import com.google.gson.Gson
import com.google.gson.JsonParser
import com.google.gson.reflect.TypeToken
import java.util.Date
fun Quests.toEntity(): QuestEntity {
    return QuestEntity(
        id = id,
        types = types?.let { Gson().toJson(it) },
        title = title,
        description = description,
        status = status?.name,
        date = date.time,
        startedDate = startedDate?.time,
        finishedDate = finishedDate?.time,
        rewards = rewards?.let { Gson().toJson(it) },
        details = details?.let { Gson().toJson(it) },
        streak = streak?.let { Gson().toJson(it) }
    )
}
fun QuestEntity.toDomain(): Quests {
    val gson = Gson()
    return Quests(
        id = id,
        types = types?.let {
            val listType = object : TypeToken<List>() {}.type
            gson.fromJson<List>(it, listType)
        },
        title = title,
        description = description,
        status = status?.let { QuestStatus.valueOf(it) },
        date = Date(date),
        startedDate = startedDate?.let { Date(it) },
        finishedDate = finishedDate?.let { Date(it) },
        rewards = rewards?.let { gson.fromJson(it, QuestRewards::class.java) },
        details = details?.let { gson.fromJson(it, QuestDetails::class.java) },
        streak = streak?.let { gson.fromJson(it, QuestStreak::class.java) }
    )
}



