package com.gcancino.levelingup.data.repositories
import com.gcancino.levelingup.core.Resource
import com.gcancino.levelingup.data.local.database.dao.PlayerProgressDao
import com.gcancino.levelingup.data.local.database.dao.PlayerStreakDao
import com.gcancino.levelingup.data.local.database.dao.dailyTasks.DailyTaskDao
import com.gcancino.levelingup.data.local.database.dao.dailyTasks.EveningEntryDao
import com.gcancino.levelingup.data.local.database.dao.dailyTasks.MorningEntryDao
import com.gcancino.levelingup.data.local.database.dao.dailyTasks.PenaltyEventDao
import com.gcancino.levelingup.data.local.database.entities.dailyTasks.DailyTaskEntity
import com.gcancino.levelingup.data.local.database.entities.dailyTasks.EveningEntryEntity
import com.gcancino.levelingup.data.local.database.entities.dailyTasks.MorningEntryEntity
import com.gcancino.levelingup.data.local.database.entities.dailyTasks.PenaltyEventEntity
import com.gcancino.levelingup.data.local.database.mappers.toDomain
import com.gcancino.levelingup.data.local.database.mappers.toEntity
import com.gcancino.levelingup.domain.logic.LevelCalculator
import com.gcancino.levelingup.domain.models.dailyTasks.DailyTask
import com.gcancino.levelingup.domain.models.dailyTasks.EveningEntry
import com.gcancino.levelingup.domain.models.dailyTasks.MorningEntry
import com.gcancino.levelingup.domain.models.dailyTasks.PenaltyEvent
import com.gcancino.levelingup.domain.repositories.DailyTasksRepository
import com.gcancino.levelingup.domain.repositories.PlayerRepository
import com.google.firebase.auth.FirebaseAuth
import com.google.firebase.firestore.FirebaseFirestore
import com.google.gson.Gson
import kotlinx.coroutines.flow.Flow
import kotlinx.coroutines.flow.map
import kotlinx.coroutines.tasks.await
import timber.log.Timber
import java.util.Calendar
import java.util.Date
import java.util.UUID
import javax.inject.Inject
class DailyTasksRepositoryImpl @Inject constructor(
    private val morningDao: MorningEntryDao,
    private val eveningDao: EveningEntryDao,
    private val taskDao: DailyTaskDao,
    private val penaltyDao: PenaltyEventDao,
    private val playerProgressDao: PlayerProgressDao,
    private val playerStreakDao: PlayerStreakDao,
    private val playerRepository: PlayerRepository,
    private val firestore: FirebaseFirestore,
    private val auth: FirebaseAuth
) : DailyTasksRepository {
    private val TAG = "DailyRepository"
    private fun todayBoundaries(): Pair {
        val cal = Calendar.getInstance().apply {
            set(Calendar.HOUR_OF_DAY, 0); set(Calendar.MINUTE, 0)
            set(Calendar.SECOND, 0);      set(Calendar.MILLISECOND, 0)
        }
        val start = cal.timeInMillis
        cal.add(Calendar.DAY_OF_YEAR, 1)
        return Pair(start, cal.timeInMillis)
    }
    override suspend fun saveMorningEntry(entry: MorningEntry): Resource {
        return try {
            morningDao.insert(entry.toEntity())
            Timber.tag(TAG).i("✔ Morning entry saved → ${entry.answers.size} answers")
            Resource.Success(Unit)
        } catch (e: Exception) {
            Timber.tag(TAG).e(e, "saveMorningEntry() failed")
            Resource.Error(e.message ?: "Failed to save morning entry")
        }
    }
    override fun observeMorningCompletedToday(uID: String): Flow {
        val (start, end) = todayBoundaries()
        return morningDao.countForDay(uID, start, end)
            .map { it > 0 }
    }
    override suspend fun getTodaysMorningEntry(uID: String): MorningEntry? {
        val (start, end) = todayBoundaries()
        return morningDao.getForDay(uID, start, end)?.toDomain()
    }
    override suspend fun saveEveningEntry(entry: EveningEntry): Resource {
        return try {
            eveningDao.insert(entry.toEntity())
            Timber.tag(TAG).i("✔ Evening entry saved → ${entry.answers.size} answers")
            Resource.Success(Unit)
        } catch (e: Exception) {
            Timber.tag(TAG).e(e, "saveEveningEntry() failed")
            Resource.Error(e.message ?: "Failed to save evening entry")
        }
    }
    override fun observeEveningCompletedToday(uID: String): Flow {
        val (start, end) = todayBoundaries()
        return eveningDao.countForDay(uID, start, end)
            .map { it > 0 }
    }
    override suspend fun saveTasks(tasks: List): Resource {
        return try {
            taskDao.insertAll(tasks.map { it.toEntity() })
            Timber.tag(TAG).i("✔ ${tasks.size} task(s) saved to Room")
            Resource.Success(Unit)
        } catch (e: Exception) {
            Timber.tag(TAG).e(e, "saveTasks() failed")
            Resource.Error(e.message ?: "Failed to save tasks")
        }
    }
    override fun getTodaysTasks(uID: String): Flow<List> {
        val (start, end) = todayBoundaries()
        return taskDao.getTasksForDay(uID, start, end).map { it.map { e -> e.toDomain() } }
    }
    override fun getTodaysPendingTasks(uID: String): Flow<List> {
        val (start, end) = todayBoundaries()
        return taskDao.getPendingTasksForDay(uID, start, end).map { it.map { e -> e.toDomain() } }
    }
    override suspend fun countTodaysTasks(uID: String): Int {
        val (start, end) = todayBoundaries()
        return taskDao.countTasksForDay(uID, start, end)
    }
    override suspend fun completeTask(taskId: String, uID: String): Resource {
        return try {
            val (start, end) = todayBoundaries()
            val tasks        = taskDao.getTasksForDayOnce(uID, start, end)
            val task         = tasks.firstOrNull { it.id == taskId }
                ?: return Resource.Error("Task not found")
            if (task.isCompleted) {
                return Resource.Error("Task already completed")
            }
            taskDao.markCompleted(taskId, System.currentTimeMillis())
            Timber.tag(TAG).d("Task completed → id: $taskId | XP: ${task.xpReward}")
            val awardResult = playerRepository.awardXP(uID, task.xpReward)
            if (awardResult is Resource.Success) {
                Resource.Success(awardResult.data ?: 1)
            } else {
                Resource.Error(awardResult.message ?: "Failed to award XP")
            }
        } catch (e: Exception) {
            Timber.tag(TAG).e(e, "completeTask() failed")
            Resource.Error(e.message ?: "Failed to complete task")
        }
    }
    override suspend fun applyMidnightPenalty(uID: String): Resource {
        return try {
            val (start, end) = todayBoundaries()
            val incompleteTasks = taskDao.getTasksForDayOnce(uID, start, end)
                .filter { !it.isCompleted && !it.penaltyApplied }
            if (incompleteTasks.isEmpty()) {
                Timber.tag(TAG).i("No incomplete tasks → no penalty applied")
                return Resource.Success(null)
            }
            Timber.tag(TAG).d("${incompleteTasks.size} incomplete task(s) → applying penalty")
            val totalXPLost = incompleteTasks.sumOf { it.xpReward }
            playerProgressDao.getPlayerProgress(uID)?.let { progress ->
                val newXP    = maxOf(0, (progress.exp ?: 0) - totalXPLost)
                val newLevel = LevelCalculator.calculateLevel(newXP)
                playerProgressDao.updatePlayerProgress(
                    progress.copy(exp = newXP, level = newLevel)
                )
                Timber.tag(TAG).d("XP deducted → -$totalXPLost | remaining: $newXP")
            }
            val streak     = playerStreakDao.getPlayerStreak(uID)
            val streakLost = streak?.currentStreak ?: 0
            if (streak != null) {
                playerStreakDao.updateStreak(uID, 0, Date())
            }
            Timber.tag(TAG).d("Streak reset → was $streakLost")
            incompleteTasks.forEach { taskDao.markPenaltyApplied(it.id) }
            val penaltyEvent = PenaltyEvent(
                id = UUID.randomUUID().toString(),
                uID = uID,
                date = Date(),
                xpLost = totalXPLost,
                streakLost = streakLost,
                incompleteTasks = incompleteTasks.map { it.id },
                isSynced = false
            )
            penaltyDao.insert(
                PenaltyEventEntity(
                    id = penaltyEvent.id,
                    uID = penaltyEvent.uID,
                    date = penaltyEvent.date,
                    xpLost = penaltyEvent.xpLost,
                    streakLost = penaltyEvent.streakLost,
                    incompleteTasks = Gson().toJson(penaltyEvent.incompleteTasks),
                    isSynced = false
                )
            )
            Timber.tag(TAG).i(
                "✔ Penalty applied → XP: -$totalXPLost | streak reset from $streakLost"
            )
            Resource.Success(penaltyEvent)
        } catch (e: Exception) {
            Timber.tag(TAG).e(e, "applyMidnightPenalty() failed")
            Resource.Error(e.message ?: "Penalty failed")
        }
    }
    override suspend fun getLatestPenalty(uID: String): PenaltyEvent? {
        return penaltyDao.getLatest(uID)?.let { entity ->
            PenaltyEvent(
                id              = entity.id,
                uID             = entity.uID,
                date            = entity.date,
                xpLost          = entity.xpLost,
                streakLost      = entity.streakLost,
                incompleteTasks = Gson().fromJson(
                    entity.incompleteTasks,
                    Array::class.java
                ).toList(),
                isSynced        = entity.isSynced
            )
        }
    }
    override suspend fun syncUnsynced(): Resource {
        return try {
            val morningEntries  = morningDao.getUnsynced()
            val eveningEntries  = eveningDao.getUnsynced()
            val tasks           = taskDao.getUnsynced()
            val penaltyEvents   = penaltyDao.getUnsynced()
            Timber.tag(TAG).d(
                "syncUnsynced() → morning: ${morningEntries.size} | " +
                        "evening: ${eveningEntries.size} | tasks: ${tasks.size} | " +
                        "penalties: ${penaltyEvents.size}"
            )
            if (morningEntries.isEmpty() && eveningEntries.isEmpty() &&
                tasks.isEmpty() && penaltyEvents.isEmpty()) {
                return Resource.Success(Unit)
            }
            val batch = firestore.batch()
            morningEntries.forEach { entry ->
                val ref = firestore.collection("morning_entries").document(entry.id)
                batch.set(ref, entry.toFirestoreMap())
            }
            eveningEntries.forEach { entry ->
                val ref = firestore.collection("evening_entries").document(entry.id)
                batch.set(ref, entry.toFirestoreMap())
            }
            tasks.forEach { task ->
                val ref = firestore.collection("daily_tasks").document(task.id)
                batch.set(ref, task.toFirestoreMap())
            }
            penaltyEvents.forEach { penalty ->
                val ref = firestore.collection("penalty_events").document(penalty.id)
                batch.set(ref, penalty.toFirestoreMap())
            }
            batch.commit().await()
            morningDao.markAsSynced(morningEntries.map { it.id })
            eveningDao.markAsSynced(eveningEntries.map { it.id })
            taskDao.markAsSynced(tasks.map { it.id })
            penaltyDao.markAsSynced(penaltyEvents.map { it.id })
            Timber.tag(TAG).i("✔ Sync successful")
            Resource.Success(Unit)
        } catch (e: Exception) {
            Timber.tag(TAG).e(e, "syncUnsynced() failed")
            Resource.Error(e.message ?: "Sync failed")
        }
    }
    private fun MorningEntryEntity.toFirestoreMap(): Map = mapOf(
        "id" to id,
        "uID" to uID,
        "date" to date,
        "answers" to answers,
        "isSynced" to true
    )
    private fun EveningEntryEntity.toFirestoreMap(): Map = mapOf(
        "id" to id,
        "uID" to uID,
        "date" to date,
        "answers" to answers,
        "isSynced" to true
    )
    private fun DailyTaskEntity.toFirestoreMap(): Map = mapOf(
        "id" to id,
        "uID" to uID,
        "date" to date,
        "title" to title,
        "priority" to priority,
        "isCompleted" to isCompleted,
        "completedAt" to completedAt,
        "xpReward" to xpReward,
        "penaltyApplied" to penaltyApplied,
        "isSynced" to true
    )
    private fun PenaltyEventEntity.toFirestoreMap(): Map = mapOf(
        "id" to id,
        "uID" to uID,
        "date" to date,
        "xpLost" to xpLost,
        "streakLost" to streakLost,
        "incompleteTasks" to incompleteTasks,
        "isSynced" to true
    )
}



package com.gcancino.levelingup.data.repositories
import com.gcancino.levelingup.core.Resource
import com.gcancino.levelingup.data.local.database.dao.ExerciseDao
import com.gcancino.levelingup.data.local.database.entities.ExerciseBlockEntity
import com.gcancino.levelingup.data.local.database.entities.ExerciseEntity
import com.gcancino.levelingup.data.local.database.entities.ExerciseSetEntity
import com.gcancino.levelingup.data.local.database.entities.SetLogEntity
import com.gcancino.levelingup.data.local.database.entities.TrainingSessionEntity
import com.gcancino.levelingup.domain.models.exercise.*
import com.gcancino.levelingup.domain.repositories.ExerciseRepository
import com.google.firebase.auth.FirebaseAuth
import com.google.firebase.firestore.FirebaseFirestore
import com.google.firebase.firestore.Query
import com.google.firebase.Timestamp
import kotlinx.coroutines.ExperimentalCoroutinesApi
import kotlinx.coroutines.channels.awaitClose
import kotlinx.coroutines.flow.*
import kotlinx.coroutines.tasks.await
import timber.log.Timber
import java.util.*
import javax.inject.Inject
import kotlinx.serialization.json.*
import java.time.LocalDate
@OptIn(ExperimentalCoroutinesApi::class)
class ExerciseRepositoryImpl @Inject constructor(
    private val firestore: FirebaseFirestore,
    private val auth: FirebaseAuth,
    private val exerciseDao: ExerciseDao
) : ExerciseRepository {
    private val TAG = "ExerciseRepository"
    private val json = Json {
        ignoreUnknownKeys = true
        coerceInputValues = true
    }
    private fun Any?.toJsonElement(): JsonElement = when (this) {
        null -> JsonNull
        is Boolean -> JsonPrimitive(this)
        is Number -> JsonPrimitive(this)
        is String -> JsonPrimitive(this)
        is Timestamp -> JsonPrimitive(this.toDate().time)
        is Date -> JsonPrimitive(this.time)
        is Map<*, *> -> JsonObject(map { it.key.toString() to it.value.toJsonElement() }.toMap())
        is List<*> -> JsonArray(map { it.toJsonElement() })
        else -> JsonPrimitive(this.toString())
    }
    private inline fun  Map.toSerializableObject(): T =
        json.decodeFromJsonElement(this.toJsonElement())
    override suspend fun syncWeek(date: LocalDate): Resource {
        Timber.tag(TAG).d("syncWeek() → no-op, Firestore is source of truth")
        return Resource.Success(Unit)
    }
    override fun getTodaysSession(): Flow<Resource> {
        Timber.tag(TAG).d("getTodaysSession() called")
        return getSessionForDate(Date())
    }
    override fun getSessionForDate(date: Date): Flow<Resource> = flow {
        emit(Resource.Loading())
        Timber.tag(TAG).d("getSessionForDate() → querying Firestore for: $date")
        try {
            val cal = Calendar.getInstance().apply {
                time = date
                set(Calendar.HOUR_OF_DAY, 0)
                set(Calendar.MINUTE, 0)
                set(Calendar.SECOND, 0)
                set(Calendar.MILLISECOND, 0)
            }
            val startOfDay = cal.time
            cal.add(Calendar.DAY_OF_YEAR, 1)
            val endOfDay = cal.time
            Timber.tag(TAG).d("Firestore query window → $startOfDay to $endOfDay")
            val snapshot = firestore.collection("sessions")
                .whereGreaterThanOrEqualTo("date", startOfDay)
                .whereLessThan("date", endOfDay)
                .get()
                .await()
            Timber.tag(TAG).d("Firestore returned ${snapshot.documents.size} session(s)")
            val sessionDoc = snapshot.documents.firstOrNull()
            if (sessionDoc == null) {
                Timber.tag(TAG).w("✘ No session for $date → emitting null")
                emit(Resource.Success(null))
                return@flow
            }
            val data = sessionDoc.data
            if (data == null) {
                Timber.tag(TAG).w("Session ${sessionDoc.id} has null data")
                emit(Resource.Success(null))
                return@flow
            }
            Timber.tag(TAG).d("Session found → id: ${sessionDoc.id}")
            var session = data.toSerializableObject().copy(id = sessionDoc.id)
            val blocksSnapshot = firestore
                .collection("sessions")
                .document(sessionDoc.id)
                .collection("blocks")
                .orderBy("order", Query.Direction.ASCENDING)
                .get()
                .await()
            Timber.tag(TAG).d("Blocks fetched: ${blocksSnapshot.documents.size}")
            val blocks = blocksSnapshot.documents.mapNotNull { blockDoc ->
                val blockData = blockDoc.data ?: run {
                    Timber.tag(TAG).w("Block ${blockDoc.id} has null data — skipping")
                    return@mapNotNull null
                }
                blockData.toSerializableObject().copy(
                    id        = blockDoc.id,
                    sessionId = sessionDoc.id
                )
            }
            session = session.copy(blocks = blocks)
            Timber.tag(TAG).i(
                "✔ Session assembled → name: '${session.name}' | " +
                        "blocks: ${blocks.size} | exercises: ${blocks.sumOf { it.exercises.size }}"
            )
            emit(Resource.Success(session))
        } catch (e: Exception) {
            Timber.tag(TAG).e(e, "getSessionForDate() failed for: $date")
            emit(Resource.Error(e.message ?: "Error loading session"))
        }
    }
    override suspend fun toggleSetLog(
        sessionId: String,
        exerciseId: String,
        setIndex: Int,
        isCompleted: Boolean
    ) {
        if (isCompleted) {
            Timber.tag(TAG).d("Inserting set log → session: $sessionId | exercise: $exerciseId | set: $setIndex")
            exerciseDao.insertSetLog(
                SetLogEntity(
                    sessionId    = sessionId,
                    exerciseId   = exerciseId,
                    setIndex     = setIndex,
                    actualReps   = null,
                    actualWeight = null,
                    isCompleted  = true
                )
            )
        } else {
            Timber.tag(TAG).d("Deleting set log → session: $sessionId | exercise: $exerciseId | set: $setIndex")
            exerciseDao.deleteSetLog(sessionId, exerciseId, setIndex)
        }
    }
    override fun getCompletedSetsForSession(sessionId: String): Flow<Set> {
        return exerciseDao.getLogsForSession(sessionId).map { logs ->
            logs.map { it.setIndex }.toSet()
        }
    }
    override fun getLogsForSessionAsMap(sessionId: String): Flow<Map<String, Set>> {
        Timber.tag(TAG).d("getLogsForSessionAsMap() → session: $sessionId")
        return exerciseDao.getLogsForSession(sessionId).map { logs ->
            logs
                .groupBy { it.exerciseId }
                .mapValues { (_, entries) -> entries.map { it.setIndex }.toSet() }
                .also {
                    Timber.tag(TAG).d(
                        "Restored completed sets map → " +
                                "${it.values.sumOf { set -> set.size }} total sets across ${it.size} exercise(s)"
                    )
                }
        }
    }
    override fun getOneRepMaxes(): Flow<Resource<List>> = callbackFlow {
        trySend(Resource.Loading())
        val userId = auth.currentUser?.uid ?: "84tDYVTSukQ0UcuuqqaNLytXcQv1"
        Timber.tag(TAG).d("Subscribing to 1RM listener for user: $userId")
        val registration = firestore.collection("exercises_1rm")
            .whereEqualTo("uID", userId)
            .addSnapshotListener { snapshot, error ->
                if (error != null) {
                    Timber.tag(TAG).e(error, "1RM snapshot error")
                    trySend(Resource.Error(error.message ?: "Error fetching 1RM"))
                    return@addSnapshotListener
                }
                val oneRepMaxes = snapshot?.documents?.flatMap { doc ->
                    (doc.data ?: emptyMap())
                        .filter { (key, value) -> key != "uID" && key != "date" && value is Number }
                        .map { (key, value) ->
                            OneRepMax(
                                id           = doc.id,
                                userId       = userId,
                                exerciseId   = key,
                                exerciseName = key,
                                weight       = (value as Number).toDouble()
                            )
                        }
                } ?: emptyList()
                Timber.tag(TAG).d("1RM update → ${oneRepMaxes.size} entries")
                trySend(Resource.Success(oneRepMaxes))
            }
        awaitClose {
            Timber.tag(TAG).d("Removing 1RM listener")
            registration.remove()
        }
    }
    override suspend fun saveTodaySessionLocally(session: TrainingSession): Resource {
        return try {
            Timber.tag(TAG).d("saveTodaySessionLocally() → saving session: ${session.id}")
            exerciseDao.insertTrainingSessions(listOf(
                TrainingSessionEntity(
                    id           = session.id,
                    completed    = session.completed,
                    macrocycleId = session.macrocycleId,
                    mesocycleId  = session.mesocycleId,
                    microcycleId = session.microcycleId,
                    date         = session.date,
                    name         = session.name
                )
            ))
            Timber.tag(TAG).d("✔ Session inserted into Room")
            val blockEntities = session.blocks.map { block ->
                ExerciseBlockEntity(
                    id = block.id,
                    sessionId = session.id,
                    type = block.type,
                    sets = block.sets,
                    restBetweenExercises = block.restBetweenExercises,
                    restAfterBlock = block.restAfterBlock,
                    order = block.order
                )
            }
            exerciseDao.insertExerciseBlocks(blockEntities)
            Timber.tag(TAG).d("✔ ${blockEntities.size} block(s) inserted into Room")
            val exerciseEntities = mutableListOf()
            val setEntities      = mutableListOf()
            session.blocks.forEach { block ->
                block.exercises.forEachIndexed { exIdx, exercise ->
                    exerciseEntities.add(
                        ExerciseEntity(
                            id      = exercise.id,
                            blockId = block.id,
                            name    = exercise.name,
                            role    = exercise.exerciseRole,
                            notes   = exercise.notes,
                            order   = exIdx
                        )
                    )
                    exercise.sets.forEachIndexed { setIdx, set ->
                        setEntities.add(
                            ExerciseSetEntity(
                                id            = set.id,
                                exerciseId    = exercise.id,
                                reps          = set.reps,
                                intensity     = set.intensity,
                                intensityType = set.intensityType,
                                restSeconds   = set.restSeconds,
                                order         = setIdx
                            )
                        )
                    }
                }
            }
            exerciseDao.insertExercises(exerciseEntities)
            Timber.tag(TAG).d("✔ ${exerciseEntities.size} exercise(s) inserted into Room")
            exerciseDao.insertExerciseSets(setEntities)
            Timber.tag(TAG).d("✔ ${setEntities.size} set(s) inserted into Room")
            Timber.tag(TAG).i("✔ Today's session fully saved locally")
            Resource.Success(Unit)
        } catch (e: Exception) {
            Timber.tag(TAG).e(e, "saveTodaySessionLocally() failed")
            Resource.Error(e.message ?: "Failed to save session locally")
        }
    }
}



package com.gcancino.levelingup.data.repositories
import com.gcancino.levelingup.core.Resource
import com.gcancino.levelingup.data.local.database.dao.DailyStandardEntryDao
import com.gcancino.levelingup.data.local.database.dao.IdentityProfileDao
import com.gcancino.levelingup.data.local.database.dao.PlayerProgressDao
import com.gcancino.levelingup.data.local.database.dao.PlayerStreakDao
import com.gcancino.levelingup.data.local.database.entities.DailyStandardEntryEntity
import com.gcancino.levelingup.data.local.database.entities.IdentityProfileEntity
import com.gcancino.levelingup.domain.logic.LevelCalculator
import com.gcancino.levelingup.domain.models.identity.DailyStandardEntry
import com.gcancino.levelingup.domain.models.identity.IdentityProfile
import com.gcancino.levelingup.domain.models.identity.IdentityScore
import com.gcancino.levelingup.domain.models.identity.IdentityStandard
import com.gcancino.levelingup.domain.models.identity.Role
import com.gcancino.levelingup.domain.models.identity.StandardType
import com.gcancino.levelingup.domain.repositories.IdentityRepository
import com.google.firebase.Timestamp
import com.google.firebase.firestore.FirebaseFirestore
import com.google.gson.Gson
import com.google.gson.reflect.TypeToken
import kotlinx.coroutines.flow.Flow
import kotlinx.coroutines.flow.combine
import kotlinx.coroutines.flow.map
import kotlinx.coroutines.tasks.await
import timber.log.Timber
import java.util.Calendar
import java.util.Date
import java.util.UUID
import javax.inject.Inject
class IdentityRepositoryImpl @Inject constructor(
    private val identityProfileDao: IdentityProfileDao,
    private val standardEntryDao: DailyStandardEntryDao,
    private val playerProgressDao: PlayerProgressDao,
    private val playerStreakDao: PlayerStreakDao,
    private val firestore: FirebaseFirestore
) : IdentityRepository {
    private val TAG  = "IdentityRepository"
    private val gson = Gson()
    private fun todayBoundaries(): Pair {
        val cal = Calendar.getInstance().apply {
            set(Calendar.HOUR_OF_DAY, 0); set(Calendar.MINUTE, 0)
            set(Calendar.SECOND, 0);      set(Calendar.MILLISECOND, 0)
        }
        val start = cal.timeInMillis
        cal.add(Calendar.DAY_OF_YEAR, 1)
        return start to cal.timeInMillis
    }
    private val rolesType = object : TypeToken<List>() {}.type
    private val standardsType = object : TypeToken<List>() {}.type
    private fun IdentityProfileEntity.toDomain() = IdentityProfile(
        id = id,
        uID = uID,
        identityStatement = identityStatement,
        roles = gson.fromJson(roles, rolesType),
        standards = gson.fromJson(standards, standardsType),
        createdAt = createdAt,
        isSynced = isSynced
    )
    private fun IdentityProfile.toEntity() = IdentityProfileEntity(
        id = id,
        uID = uID,
        identityStatement = identityStatement,
        roles = gson.toJson(roles),
        standards = gson.toJson(standards),
        createdAt = createdAt,
        isSynced = isSynced
    )
    private fun DailyStandardEntryEntity.toDomain() = DailyStandardEntry(
        id = id,
        uID = uID,
        standardId = standardId,
        standardTitle = standardTitle,
        standardType = StandardType.valueOf(standardType),
        roleId = roleId,
        roleName = roleName,
        date = date,
        isCompleted = isCompleted,
        completedAt = completedAt,
        xpAwarded = xpAwarded,
        autoValidated = autoValidated,
        penaltyApplied = penaltyApplied,
        isSynced = isSynced
    )
    override suspend fun saveIdentityProfile(profile: IdentityProfile): Resource {
        return try {
            identityProfileDao.insert(profile.toEntity())
            Timber.tag(TAG).i(
                "✔ IdentityProfile guardado → '${profile.identityStatement}' | " +
                        "${profile.roles.size} roles | ${profile.standards.size} estándares"
            )
            Resource.Success(Unit)
        } catch (e: Exception) {
            Timber.tag(TAG).e(e, "saveIdentityProfile() falló")
            Resource.Error(e.message ?: "Error guardando perfil de identidad")
        }
    }
    override fun observeIdentityProfile(uID: String): Flow =
        identityProfileDao.observe(uID).map { it?.toDomain() }
    override suspend fun hasIdentityProfile(uID: String): Boolean =
        identityProfileDao.count(uID) > 0
    override suspend fun generateTodayEntries(uID: String): Resource {
        return try {
            val (start, end) = todayBoundaries()
            val profile = identityProfileDao.get(uID)
                ?: return Resource.Success(Unit)
            val roles: List = gson.fromJson(profile.roles, rolesType)
            val standards: List = gson.fromJson(profile.standards, standardsType)
            val existingIds = standardEntryDao
                .getExistingStandardIdsForDay(uID, start, end)
                .toSet()
            val roleMap = roles.associateBy { it.id }
            val newEntries = standards
                .filter { it.isActive && it.id !in existingIds }
                .mapNotNull { standard ->
                    val role = roleMap[standard.roleId] ?: run {
                        Timber.tag(TAG).w("Rol '${standard.roleId}' no encontrado para estándar '${standard.title}'")
                        return@mapNotNull null
                    }
                    DailyStandardEntryEntity(
                        id = UUID.randomUUID().toString(),
                        uID = uID,
                        standardId = standard.id,
                        standardTitle = standard.title,
                        standardType = standard.type.name,
                        roleId = standard.roleId,
                        roleName = role.name,
                        date = Date(),
                        isCompleted = false,
                        xpAwarded = standard.xpReward,
                        autoValidated = false,
                        penaltyApplied = false,
                        isSynced = false
                    )
                }
            if (newEntries.isNotEmpty()) {
                standardEntryDao.insertAll(newEntries)
                Timber.tag(TAG).i("✔ ${newEntries.size} entrada(s) generadas para hoy")
            }
            Resource.Success(Unit)
        } catch (e: Exception) {
            Timber.tag(TAG).e(e, "generateTodayEntries() falló")
            Resource.Error(e.message ?: "Error generando entradas")
        }
    }
    override fun observeTodayScore(uID: String): Flow {
        val (start, end) = todayBoundaries()
        return combine(
            standardEntryDao.observeForDay(uID, start, end),
            identityProfileDao.observe(uID)
        ) { entries, profileEntity ->
            val roles = profileEntity?.let {
                gson.fromJson<List>(it.roles, rolesType)
            } ?: emptyList()
            IdentityScore.calculate(entries.map { it.toDomain() }, roles)
        }
    }
    override fun observeTodayEntries(uID: String): Flow<List> {
        val (start, end) = todayBoundaries()
        return standardEntryDao.observeForDay(uID, start, end)
            .map { it.map { e -> e.toDomain() } }
    }
    override fun observePendingEntries(uID: String): Flow<List> {
        val (start, end) = todayBoundaries()
        return standardEntryDao.observePendingForDay(uID, start, end)
            .map { it.map { e -> e.toDomain() } }
    }
    override suspend fun completeStandard(entryId: String, uID: String): Resource {
        return try {
            val (start, end) = todayBoundaries()
            val entry = standardEntryDao.getForDay(uID, start, end)
                .firstOrNull { it.id == entryId }
                ?: return Resource.Error("Entrada no encontrada")
            if (entry.isCompleted) return Resource.Error("Estándar ya completado")
            standardEntryDao.markCompleted(
                entryId     = entryId,
                completedAt = System.currentTimeMillis(),
                xpAwarded   = entry.xpAwarded
            )
            awardXPToPlayer(uID, entry.xpAwarded)
            Timber.tag(TAG).d(
                "Estándar completado → '${entry.standardTitle}' " +
                        "[${entry.roleName}] | +${entry.xpAwarded} XP"
            )
            Resource.Success(entry.xpAwarded)
        } catch (e: Exception) {
            Timber.tag(TAG).e(e, "completeStandard() falló")
            Resource.Error(e.message ?: "Error completando estándar")
        }
    }
    override suspend fun autoValidateTraining(uID: String): Resource {
        return try {
            val (start, end) = todayBoundaries()
            val profile = identityProfileDao.get(uID)
            val standards: List = profile?.let {
                gson.fromJson(it.standards, standardsType)
            } ?: emptyList()
            val trainingXP = standards
                .filter { it.type == StandardType.TRAINING && it.isActive }
                .sumOf { it.xpReward }
                .takeIf { it > 0 } ?: 100
            standardEntryDao.autoValidateTraining(
                uID         = uID,
                startOfDay  = start,
                endOfDay    = end,
                completedAt = System.currentTimeMillis(),
                xpAwarded   = trainingXP
            )
            awardXPToPlayer(uID, trainingXP)
            Timber.tag(TAG).i("✔ Estándar(es) TRAINING auto-validado(s) → +$trainingXP XP")
            Resource.Success(Unit)
        } catch (e: Exception) {
            Timber.tag(TAG).e(e, "autoValidateTraining() falló")
            Resource.Error(e.message ?: "Error en auto-validación")
        }
    }
    override suspend fun applyMidnightPenalty(uID: String): Resource {
        return try {
            val (start, end) = todayBoundaries()
            val incomplete   = standardEntryDao.getIncompleteForDay(uID, start, end)
            if (incomplete.isEmpty()) {
                Timber.tag(TAG).i("Sin incumplimientos — sin penalización")
                return Resource.Success(Unit)
            }
            val totalXPLost = incomplete.sumOf { it.xpAwarded }
            val progress = playerProgressDao.getPlayerProgress(uID)
            if (progress != null) {
                val newXP    = maxOf(0, (progress.exp ?: 0) - totalXPLost)
                val newLevel = LevelCalculator.calculateLevel(newXP)
                playerProgressDao.updatePlayerProgress(
                    progress.copy(exp = newXP, level = newLevel)
                )
            }
            val streak = playerStreakDao.getPlayerStreak(uID)
            val streakLost = streak?.currentStreak ?: 0
            if (streak != null) playerStreakDao.updateStreak(uID, 0, Date())
            incomplete.forEach { standardEntryDao.markPenaltyApplied(it.id) }
            Timber.tag(TAG).i(
                "%snull", "✔ Penalización aplicada → " +
                        "${incomplete.size} estándar(es) incumplido(s) | "
            )
            Resource.Success(Unit)
        } catch (e: Exception) {
            Timber.tag(TAG).e(e, "applyMidnightPenalty() falló")
            Resource.Error(e.message ?: "Error aplicando penalización")
        }
    }
    override suspend fun syncUnsynced(): Resource {
        return try {
            val profiles = identityProfileDao.getUnsynced()
            val entries  = standardEntryDao.getUnsynced()
            if (profiles.isEmpty() && entries.isEmpty()) return Resource.Success(Unit)
            val batch = firestore.batch()
            profiles.forEach { profile ->
                val ref = firestore.collection("identity_profiles").document(profile.id)
                batch.set(ref, profile.toFirestoreMap())
            }
            entries.forEach { entry ->
                val ref = firestore.collection("daily_standard_entries").document(entry.id)
                batch.set(ref, entry.toFirestoreMap())
            }
            batch.commit().await()
            Timber.tag(TAG).i("✔ Identity sync completado")
            if (profiles.isNotEmpty()) identityProfileDao.markAsSynced(profiles.map { it.id })
            if (entries.isNotEmpty())  standardEntryDao.markAsSynced(entries.map { it.id })
            Resource.Success(Unit)
        } catch (e: Exception) {
            Timber.tag(TAG).e(e, "syncUnsynced() falló")
            Resource.Error(e.message ?: "Sync fallido")
        }
    }
    private suspend fun awardXPToPlayer(uID: String, xp: Int) {
        val progress = playerProgressDao.getPlayerProgress(uID) ?: return
        val newXP    = (progress.exp ?: 0) + xp
        val newLevel = LevelCalculator.calculateLevel(newXP)
        playerProgressDao.updatePlayerProgress(progress.copy(exp = newXP, level = newLevel))
        Timber.tag(TAG).d("XP otorgado → +$xp | total: $newXP | nivel: $newLevel")
    }
    private fun IdentityProfileEntity.toFirestoreMap() = mapOf(
        "id" to id,
        "uID" to uID,
        "identityStatement" to identityStatement,
        "roles" to roles,
        "standards" to standards,
        "createdAt" to Timestamp(createdAt)
    )
    private fun DailyStandardEntryEntity.toFirestoreMap() = mapOf(
        "id"             to id,
        "uID"            to uID,
        "standardId"     to standardId,
        "standardTitle"  to standardTitle,
        "standardType"   to standardType,
        "roleId"         to roleId,
        "roleName"       to roleName,
        "date"           to Timestamp(date),
        "isCompleted"    to isCompleted,
        "completedAt"    to completedAt?.let { Timestamp(it) },
        "xpAwarded"      to xpAwarded,
        "autoValidated"  to autoValidated,
        "penaltyApplied" to penaltyApplied
    )
}



package com.gcancino.levelingup.data.repositories
import android.content.Context
import android.net.Uri
import com.gcancino.levelingup.core.Config
import com.gcancino.levelingup.core.Resource
import com.gcancino.levelingup.data.local.database.dao.NutritionEntryDao
import com.gcancino.levelingup.data.local.database.entities.NutritionEntryEntity
import com.gcancino.levelingup.domain.logic.TimeProvider
import com.gcancino.levelingup.domain.models.nutrition.*
import com.gcancino.levelingup.domain.repositories.NutritionRepository
import com.google.firebase.firestore.FirebaseFirestore
import com.google.firebase.storage.FirebaseStorage
import com.google.gson.Gson
import com.google.gson.reflect.TypeToken
import dagger.hilt.android.qualifiers.ApplicationContext
import kotlinx.coroutines.flow.Flow
import kotlinx.coroutines.flow.map
import kotlinx.coroutines.tasks.await
import okhttp3.MediaType.Companion.toMediaType
import okhttp3.MultipartBody
import okhttp3.OkHttpClient
import okhttp3.Request
import okhttp3.RequestBody.Companion.asRequestBody
import org.json.JSONObject
import timber.log.Timber
import java.io.File
import java.io.FileOutputStream
import java.util.*
import java.util.concurrent.TimeUnit
import javax.inject.Inject
class NutritionRepositoryImpl @Inject constructor(
    @param:ApplicationContext private val context: Context,
    private val nutritionDao: NutritionEntryDao,
    private val timeProvider: TimeProvider,
    private val firestore: FirebaseFirestore,
    private val storage: FirebaseStorage,
    private val gson: Gson
) : NutritionRepository {
    private val TAG = "NutritionRepository"
    private val FLASK_BASE_URL = Config.BACKEND_ENDPOINT
    private val http = OkHttpClient.Builder()
        .connectTimeout(30, TimeUnit.SECONDS)
        .readTimeout(90, TimeUnit.SECONDS)
        .build()
    override suspend fun analyzeFood(
        uID: String,
        imageUri: Uri,
        identityStatement: String,
        nutritionStandardTitles: List
    ): Resource {
        return try {
            val tempFile = copyUriToTempFile(imageUri)
                ?: return Resource.Error("Failed to read image")
            val standardsJson = gson.toJson(
                nutritionStandardTitles.mapIndexed { i, title ->
                    mapOf("id" to "s$i", "title" to title)
                }
            )
            val requestBody = MultipartBody.Builder()
                .setType(MultipartBody.FORM)
                .addFormDataPart(
                    "image", tempFile.name,
                    tempFile.asRequestBody("image/jpeg".toMediaType())
                )
                .addFormDataPart("identity_statement", identityStatement)
                .addFormDataPart("nutrition_standards", standardsJson)
                .build()
            val request = Request.Builder()
                .url("$FLASK_BASE_URL/nutrition/analyze")
                .post(requestBody)
                .build()
            val response = http.newCall(request).execute()
            tempFile.delete()
            if (!response.isSuccessful) {
                return Resource.Error("Analysis failed: ${response.code}")
            }
            val json = JSONObject(response.body.string())
            val photoUrl = uploadPhotoToStorage(uID, imageUri)
            val entry = parseAndSave(uID, json, photoUrl)
            Timber.tag(TAG).i("✔ Food analyzed → ${entry.foodIdentified} | ${entry.alignment}")
            Resource.Success(entry)
        } catch (e: Exception) {
            Timber.tag(TAG).e(e, "analyzeFood() failed")
            Resource.Error(e.message ?: "Analysis failed")
        }
    }
    override fun observeTodayEntries(uID: String): Flow<List> {
        val (start, end) = timeProvider.dayBoundaries(timeProvider.today())
        return nutritionDao.observeForDay(uID, start, end)
            .map { it.map { e -> e.toDomain() } }
    }
    override fun observeTodayMacros(uID: String): Flow {
        return observeTodayEntries(uID).map { entries ->
            entries.fold(MacroSummary(0, 0f, 0f, 0f, 0f)) { acc, e -> acc + e.macroSummary }
        }
    }
    override fun observeAlignedCountToday(uID: String): Flow {
        val (start, end) = timeProvider.dayBoundaries(timeProvider.today())
        return nutritionDao.countAlignedForDay(uID, start, end)
    }
    override fun observeRecentEntries(uID: String): Flow<List> =
        nutritionDao.observeRecent(uID).map { it.map { e -> e.toDomain() } }
    override suspend fun syncUnsynced(): Resource {
        return try {
            val unsynced = nutritionDao.getUnsynced()
            if (unsynced.isEmpty()) return Resource.Success(Unit)
            val batch = firestore.batch()
            unsynced.forEach { entry ->
                val ref = firestore.collection("nutrition_entries").document(entry.id)
                batch.set(ref, entry.toFirestoreMap())
            }
            batch.commit().await()
            nutritionDao.markAsSynced(unsynced.map { it.id })
            Timber.tag(TAG).i("✔ Nutrition sync complete")
            Resource.Success(Unit)
        } catch (e: Exception) {
            Timber.tag(TAG).e(e, "syncUnsynced() failed")
            Resource.Error(e.message ?: "Sync failed")
        }
    }
    private fun parseAndSave(uID: String, json: JSONObject, photoUrl: String): NutritionEntry {
        val macros = json.optJSONObject("macros")
        val micros = json.optJSONObject("micros")
        val highlights: List = micros?.optJSONArray("highlights")?.let { arr ->
            (0 until arr.length()).map { arr.getString(it) }
        } ?: emptyList()
        val concerns: List = micros?.optJSONArray("concerns")?.let { arr ->
            (0 until arr.length()).map { arr.getString(it) }
        } ?: emptyList()
        val entry = NutritionEntry(
            id              = UUID.randomUUID().toString(),
            uID             = uID,
            date            = Date(),
            foodIdentified  = json.optString("food_identified", "Unknown food"),
            photoUrl        = photoUrl,
            calories        = json.optInt("total_calories_computed", 0),
            proteinG        = macros?.optDouble("protein_g", 0.0)?.toFloat() ?: 0f,
            carbsG          = macros?.optDouble("carbs_g", 0.0)?.toFloat() ?: 0f,
            fatsG           = macros?.optDouble("fats_g", 0.0)?.toFloat() ?: 0f,
            fiberG          = macros?.optDouble("fiber_g", 0.0)?.toFloat() ?: 0f,
            microHighlights = highlights,
            microConcerns   = concerns,
            processingLevel = parseProcessingLevel(json.optString("processing_level")),
            alignment       = parseAlignment(json.optString("alignment")),
            alignmentReason = json.optString("alignment_reason", ""),
            suggestion      = json.optString("suggestion", ""),
            isSynced        = false
        )
        // Fire-and-forget Room insert — caller collects from Flow
        kotlinx.coroutines.runBlocking {
            nutritionDao.insert(entry.toEntity())
        }
        return entry
    }
    private fun copyUriToTempFile(uri: Uri): File? {
        return try {
            val inputStream = context.contentResolver.openInputStream(uri) ?: return null
            val tempFile    = File.createTempFile("food_", ".jpg", context.cacheDir)
            FileOutputStream(tempFile).use { out -> inputStream.copyTo(out) }
            inputStream.close()
            tempFile
        } catch (e: Exception) {
            Timber.tag(TAG).e(e, "copyUriToTempFile() failed")
            null
        }
    }
    private suspend fun uploadPhotoToStorage(uID: String, uri: Uri): String {
        return try {
            val ref  = storage.reference.child("nutrition/$uID/${UUID.randomUUID()}.jpg")
            ref.putFile(uri).await()
            ref.downloadUrl.await().toString()
        } catch (e: Exception) {
            Timber.tag(TAG).w("Photo upload failed (non-fatal): ${e.message}")
            "" // non-fatal — macros still saved
        }
    }
    private fun parseAlignment(value: String) = when (value.lowercase()) {
        "aligned"    -> NutritionAlignment.ALIGNED
        "misaligned" -> NutritionAlignment.MISALIGNED
        else         -> NutritionAlignment.NEUTRAL
    }
    private fun parseProcessingLevel(value: String) = when (value.lowercase()) {
        "whole_food"           -> ProcessingLevel.WHOLE_FOOD
        "minimally_processed"  -> ProcessingLevel.MINIMALLY_PROCESSED
        "ultra_processed"      -> ProcessingLevel.ULTRA_PROCESSED
        else                   -> ProcessingLevel.UNKNOWN
    }
    private fun NutritionEntry.toEntity() = NutritionEntryEntity(
        id = id,
        uID = uID,
        date = date,
        foodIdentified = foodIdentified,
        photoUrl = photoUrl,
        calories = calories,
        proteinG = proteinG,
        carbsG = carbsG,
        fatsG = fatsG,
        fiberG = fiberG,
        microHighlights = gson.toJson(microHighlights),
        microConcerns = gson.toJson(microConcerns),
        processingLevel = processingLevel.name,
        alignment = alignment.name,
        alignmentReason = alignmentReason,
        suggestion = suggestion,
        isSynced = false
    )
    private fun NutritionEntryEntity.toDomain(): NutritionEntry {
        val listType = object : TypeToken<List>() {}.type
        return NutritionEntry(
            id              = id,
            uID             = uID,
            date            = date,
            foodIdentified  = foodIdentified,
            photoUrl        = photoUrl,
            calories        = calories,
            proteinG        = proteinG,
            carbsG          = carbsG,
            fatsG           = fatsG,
            fiberG          = fiberG,
            microHighlights = gson.fromJson(microHighlights, listType),
            microConcerns   = gson.fromJson(microConcerns, listType),
            processingLevel = parseProcessingLevel(processingLevel),
            alignment       = parseAlignment(alignment),
            alignmentReason = alignmentReason,
            suggestion      = suggestion,
            isSynced        = isSynced
        )
    }
    private fun NutritionEntryEntity.toFirestoreMap() = mapOf(
        "id"              to id,
        "uID"             to uID,
        "date"            to date,
        "foodIdentified"  to foodIdentified,
        "photoUrl"        to photoUrl,
        "calories"        to calories,
        "proteinG"        to proteinG,
        "carbsG"          to carbsG,
        "fatsG"           to fatsG,
        "fiberG"          to fiberG,
        "alignment"       to alignment,
        "alignmentReason" to alignmentReason,
        "isSynced"        to true
    )
}



package com.gcancino.levelingup.data.repositories
import androidx.room.withTransaction
import com.gcancino.levelingup.data.local.database.AppDatabase
import com.gcancino.levelingup.domain.repositories.PlayerRepository
import com.google.firebase.auth.FirebaseAuth
import com.google.firebase.firestore.FirebaseFirestore
import kotlinx.coroutines.flow.Flow
import kotlinx.coroutines.flow.flow
import javax.inject.Inject
import javax.inject.Singleton
import com.gcancino.levelingup.core.Resource
import com.gcancino.levelingup.data.mappers.toDomain
import com.gcancino.levelingup.data.mappers.toEntity
import com.gcancino.levelingup.domain.logic.LevelCalculator
import com.gcancino.levelingup.domain.models.Player
import com.gcancino.levelingup.domain.models.player.Attributes
import com.gcancino.levelingup.domain.models.player.CategoryType
import com.gcancino.levelingup.domain.models.player.PlayerData
import com.gcancino.levelingup.domain.models.player.Progress
import com.gcancino.levelingup.domain.models.player.Streak
import com.google.firebase.firestore.toObject
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.async
import kotlinx.coroutines.awaitAll
import kotlinx.coroutines.coroutineScope
import kotlinx.coroutines.supervisorScope
import kotlinx.coroutines.tasks.await
import kotlinx.coroutines.withContext
import timber.log.Timber
import java.util.Date
@Singleton
class PlayerRepositoryImpl @Inject constructor(
    private val auth: FirebaseAuth,
    private val db: FirebaseFirestore,
    private val localDB: AppDatabase
) : PlayerRepository {
    override fun getPlayerData(): Flow<Resource> = flow {
        val user = auth.currentUser ?: run {
            emit(Resource.Error("User not logged in"))
            return@flow
        }
        val uid = user.uid
        suspend fun fetchLocal(): PlayerData? = withContext(Dispatchers.IO) {
            val player = localDB.playerDao().getPlayer(uid)?.toDomain() ?: return@withContext null
            val attributes = localDB.playerAttributesDao().getPlayerAttributes(uid)?.toDomain()
            val progress = localDB.playerProgressDao().getPlayerProgress(uid)?.toDomain()
            val streak = localDB.playerStreakDao().getPlayerStreak(uid)?.toDomain()
            PlayerData(player, attributes, progress, streak)
        }
        val localData = fetchLocal()
        if (localData != null) {
            emit(Resource.Success(localData))
            return@flow
        }
        emit(Resource.Loading())
        val remoteData = fetchFullPlayerDataFromFirestore(uid)
        val finalData = remoteData?.let {
            PlayerData(
                player = it.player,
                attributes = it.attributes ?: createDefaultAttributes(uid),
                progress = it.progress ?: createDefaultProgress(uid),
                streak = it.streak ?: createDefaultStreak(uid)
            )
        } ?: run {
            PlayerData(
                player = Player(uid = uid),
                attributes = createDefaultAttributes(uid),
                progress = createDefaultProgress(uid),
                streak = createDefaultStreak(uid)
            )
        }
        withContext(Dispatchers.IO) {
            localDB.withTransaction {
                finalData.player?.let { localDB.playerDao().insertPLayer(it.toEntity()) }
                finalData.attributes?.let { localDB.playerAttributesDao().insertPlayerAttributes(it.toEntity()) }
                finalData.progress?.let { localDB.playerProgressDao().insertPlayerProgress(it.toEntity()) }
                finalData.streak?.let { localDB.playerStreakDao().insertPlayerStreak(it.toEntity()) }
            }
        }
        emit(Resource.Success(finalData))
    }
    override suspend fun syncMissingData(uid: String): Resource {
        return try {
            val localPlayer = withContext(Dispatchers.IO) { localDB.playerDao().getPlayer(uid) }
            if (localPlayer == null) {
                return Resource.Error("Player not found locally")
            }
            val remoteData = fetchFullPlayerDataFromFirestore(uid)
            val attributesToSave = if (remoteData?.attributes != null) {
                remoteData.attributes
            } else {
                createDefaultAttributes(uid)
            }
            val progressToSave = if (remoteData?.progress != null) {
                remoteData.progress
            } else {
                createDefaultProgress(uid)
            }
            val streakToSave = if (remoteData?.streak != null) {
                remoteData.streak
            } else {
                createDefaultStreak(uid)
            }
            withContext(Dispatchers.IO) {
                localDB.withTransaction {
                    localDB.playerAttributesDao().insertPlayerAttributes(attributesToSave.toEntity())
                    localDB.playerProgressDao().insertPlayerProgress(progressToSave.toEntity())
                    localDB.playerStreakDao().insertPlayerStreak(streakToSave.toEntity())
                }
            }
            Resource.Success(Unit)
        } catch (e: Exception) {
            Resource.Error("Sync failed: ${e.message}")
        }
    }
    override suspend fun savePlayerData(playerData: PlayerData): Resource {
        return try {
            val player = playerData.player ?: return Resource.Error("Player data is missing")
            val attributes = playerData.attributes ?: return Resource.Error("Attributes data is missing")
            val progress = playerData.progress ?: return Resource.Error("Progress data is missing")
            val streak = playerData.streak ?: return Resource.Error("Streak data is missing")
            supervisorScope {
                val firebaseDeferred = async {
                    runCatching { savePlayerToFirestore(playerData) }
                }
                val localDeferred = async(Dispatchers.IO) {
                    runCatching {
                        localDB.withTransaction {
                            localDB.playerDao().insertPLayer(player.toEntity())
                            localDB.playerAttributesDao().insertPlayerAttributes(attributes.toEntity())
                            localDB.playerProgressDao().insertPlayerProgress(progress.toEntity())
                            localDB.playerStreakDao().insertPlayerStreak(streak.toEntity())
                        }
                    }
                }
                val results = awaitAll(firebaseDeferred, localDeferred)
                val localOutcome = results[1]
                when {
                    localOutcome.isFailure -> {
                        Resource.Error("Failed to save locally: ${localOutcome.exceptionOrNull()?.message}")
                    }
                    else -> Resource.Success(Unit)
                }
            }
        } catch (e: Exception) {
            Resource.Error("Failed to save player data: ${e.message}")
        }
    }
    override fun getCurrentPlayer(): Flow<Resource> = flow {
        val user = auth.currentUser ?: run {
            emit(Resource.Success(null))
            return@flow
        }
        val localPlayer = withContext(Dispatchers.IO) {
            localDB.playerDao().getPlayer(user.uid)?.toDomain()
        }
        if (localPlayer != null) {
            emit(Resource.Success(localPlayer))
        } else {
            val firestorePlayer = fetchPlayerFromFirestore(user.uid)
            if (firestorePlayer != null) {
                withContext(Dispatchers.IO) {
                    localDB.playerDao().insertPLayer(firestorePlayer.toEntity())
                }
                emit(Resource.Success(firestorePlayer))
            } else {
                emit(Resource.Error("Player not found"))
            }
        }
    }
    override suspend fun awardXP(uid: String, xp: Int): Resource = withContext(Dispatchers.IO) {
        try {
            localDB.withTransaction {
                val currentProgress = localDB.playerProgressDao().getPlayerProgress(uid)?.toDomain()
                    ?: createDefaultProgress(uid)
                val newXP = (currentProgress.exp ?: 0) + xp
                val oldLevel = currentProgress.level ?: 1
                val newLevel = LevelCalculator.calculateLevel(newXP)
                var availablePoints = currentProgress.availablePoints
                if (newLevel > oldLevel) {
                    availablePoints += (newLevel - oldLevel) * LevelCalculator.POINTS_PER_LEVEL
                    Timber.tag("PlayerRepository").i("Level Up! $oldLevel -> $newLevel. Gained ${ (newLevel - oldLevel) * LevelCalculator.POINTS_PER_LEVEL} points.")
                }
                val updatedProgress = currentProgress.copy(
                    exp = newXP,
                    level = newLevel,
                    availablePoints = availablePoints
                )
                localDB.playerProgressDao().updateProgress(uid, availablePoints, newLevel, newXP)
                Resource.Success(newLevel)
            }
        } catch (e: Exception) {
            Resource.Error(e.message ?: "Failed to award XP")
        }
    }
    private suspend fun fetchFullPlayerDataFromFirestore(uid: String): PlayerData? {
        return try {
            coroutineScope {
                val playerDoc = db.collection("players").document(uid).get().await()
                if (!playerDoc.exists()) return@coroutineScope null
                val player = playerDoc.toObject() ?: return@coroutineScope null
                val attrDeferred = async { db.collection("player_attributes").document(uid).get().await().toObject() }
                val progDeferred = async { db.collection("player_progress").document(uid).get().await().toObject() }
                val streakDeferred = async { db.collection("player_streaks").document(uid).get().await().toObject() }
                PlayerData(player, attrDeferred.await(), progDeferred.await(), streakDeferred.await())
            }
        } catch (e: Exception) {
            null
        }
    }
    private suspend fun fetchPlayerFromFirestore(uid: String): Player? {
        return try {
            val document = db.collection("players").document(uid).get().await()
            if (document.exists()) document.toObject() else null
        } catch (e: Exception) {
            null
        }
    }
    private suspend fun savePlayerToFirestore(playerData: PlayerData): Resource {
        return try {
            val batchWrite = db.batch()
            val pid = playerData.player!!.uid
            val playerDocRef = db.collection("players").document(pid)
            batchWrite.set(playerDocRef, playerData.player)
            val attributesDocRef = db.collection("player_attributes").document(pid)
            batchWrite.set(attributesDocRef, playerData.attributes!!)
            val progressDocRef = db.collection("player_progress").document(pid)
            batchWrite.set(progressDocRef, playerData.progress!!)
            val streakDocRef = db.collection("player_streaks").document(pid)
            batchWrite.set(streakDocRef, playerData.streak!!)
            batchWrite.commit().await()
            Resource.Success(Unit)
        } catch (e: Exception) {
            Resource.Error("Failed to save player data: ${e.message}")
        }
    }
    private fun createDefaultAttributes(uid: String): Attributes = Attributes(
        uid = uid,
        strength = 0,
        endurance = 0,
        intelligence = 0,
        mobility = 0,
        health = 0,
        finance = 0
    )
    private fun createDefaultProgress(uid: String): Progress = Progress(
        uid = uid,
        coins = 0,
        exp = 0,
        level = 1,
        availablePoints = 0,
        currentCategory = CategoryType.CATEGORY_BEGINNER
    )
    private fun createDefaultStreak(uid: String): Streak = Streak(
        uid = uid,
        currentStreak = 0,
        longestStreak = 0,
        lastStreakUpdate = Date()
    )
}



package com.gcancino.levelingup.data.repositories
import com.gcancino.levelingup.core.Resource
import com.gcancino.levelingup.data.local.database.dao.PlayerDao
import com.gcancino.levelingup.data.local.database.dao.QuestDao
import com.gcancino.levelingup.data.mappers.toDomain
import com.gcancino.levelingup.data.mappers.toEntity
import com.gcancino.levelingup.domain.models.Quests
import com.gcancino.levelingup.domain.repositories.QuestRepository
import com.google.firebase.auth.FirebaseAuth
import com.google.firebase.firestore.FirebaseFirestore
import com.google.firebase.firestore.toObject
import kotlinx.coroutines.flow.Flow
import kotlinx.coroutines.flow.flow
import kotlinx.coroutines.tasks.await
import timber.log.Timber
import kotlin.collections.emptyList
import javax.inject.Inject
import kotlin.coroutines.cancellation.CancellationException
class QuestRepositoryImpl @Inject constructor(
    private val db: FirebaseFirestore,
    private val questDao: QuestDao,
    private val playerDao: PlayerDao
) : QuestRepository {
    private val auth = FirebaseAuth.getInstance()
    override suspend fun syncQuestsFromFirestoreDos(): Resource {
        return try {
            val questsFromFirestore = getQuestsFromFirestore()
            Timber.tag("QuestRepository").d("Quests from Firestore: $questsFromFirestore")
            val questEntities = questsFromFirestore.map { it.toEntity() }
            questDao.deleteAllQuests()
            val insertionResults: List = questDao.insertQuests(questEntities)
            val successfulInserts = insertionResults.count { it > 0L }
            if (questEntities.isNotEmpty() && successfulInserts == questEntities.size) {
                Timber.tag("QuestRepository")
                    .d("Successfully inserted $successfulInserts quests into Room.")
                Resource.Success(Unit)
            } else if (questEntities.isEmpty() && successfulInserts == 0) {
                Timber.tag("QuestRepository").d("No quests from Firestore to insert.")
                Resource.Success(Unit)
            } else {
                Timber.tag("QuestRepository")
                    .w("Insertion issue: Attempted to insert ${questEntities.size}, Room reported $successfulInserts successful rowIds. Results: $insertionResults")
                Resource.Error("Failed to insert all quests. Successful: $successfulInserts/${questEntities.size}")
            }
        } catch (e: Exception) {
            Timber.tag("QuestRepository")
                .e(e, "Exception during Firestore sync or DB operation: ${e.message}")
            Resource.Error(e.message ?: "Unknown error occurred during sync")
        }
    }
    override suspend fun syncQuestsFromFirestore(): Resource {
        val player = auth.currentUser ?: return Resource.Error("Player not found")
        return try {
            val playerImprovements = playerDao.getPlayerImprovements(player.uid)
            val questsFromFirestore = getQuestsFromFirestore()
            val filteredQuests = questsFromFirestore.filter { quest ->
                quest.types?.any { questType ->
                    playerImprovements.contains(questType)
                } ?: false
            }
            questDao.deleteAllQuests()
            questDao.insertQuests(
                filteredQuests.map { it.toEntity() }
            )
            Resource.Success(Unit)
        } catch (e: Exception) {
            Resource.Error(e.message ?: "Unknown error occurred")
        }
    }
    override fun getNotStartedQuests() : Flow<List> = flow {
        try {
            questDao.getNotStartedQuests().collect { quests ->
                emit(quests.map { it.toDomain() })
            }
        } catch (_: Exception) {
            emit(emptyList())
        }
    }
    override suspend fun getQuestByQuestID(questID: String): Resource {
        return try {
            val questEntity = questDao.getQuestById(questID)
            if (questEntity != null) {
                Resource.Success(questEntity.toDomain())
            } else {
                Resource.Error("Quest not found")
            }
        } catch (e: Exception) {
            Resource.Error("Failed to get quest: ${e.message}", exception = e)
        }
    }
    private suspend fun getQuestsFromFirestore(): List {
        return try {
            val querySnapshot = db.collection("all_quests")
                .get()
                .await()
            val questsList = querySnapshot.documents.mapNotNull { documentSnapshot ->
                try {
                    documentSnapshot.toObject()
                } catch (e: Exception) {
                    Timber.tag("Firestore")
                        .e(e, "Error converting document ${documentSnapshot.id} to Quests")
                    null
                }
            }
            Timber.tag("Firestore").d("Successfully fetched ${questsList.size} quests.")
            questsList
        } catch (e: CancellationException) {
            Timber.tag("Firestore").d("Firestore getQuests operation was cancelled.")
            throw e
        } catch (e: Exception) {
            Timber.tag("Firestore").e(e, "Error fetching quests from Firestore: ${e.message}")
            emptyList()
        }
    }
    override suspend fun updateQuestStatus(questID: String) : Resource {
        return try {
            questDao.updateQuestStatusToInProgress(questID)
            Resource.Success(Unit)
        } catch (e: Exception) {
            Resource.Error(e.message ?: "Unknown error occurred")
        }
    }
}



package com.gcancino.levelingup.data.workers
import android.content.Context
import androidx.hilt.work.HiltWorker
import androidx.work.CoroutineWorker
import androidx.work.WorkerParameters
import com.gcancino.levelingup.core.Resource
import com.gcancino.levelingup.data.repositories.DailyTasksRepositoryImpl
import com.google.firebase.auth.FirebaseAuth
import dagger.assisted.Assisted
import dagger.assisted.AssistedInject
import timber.log.Timber
import androidx.core.content.edit
import com.gcancino.levelingup.domain.logic.DailyResetManager
@HiltWorker
class MidnightPenaltyWorker @AssistedInject constructor(
    @Assisted context: Context,
    @Assisted params: WorkerParameters,
    private val auth: FirebaseAuth,
    private val dailyResetManager: DailyResetManager
) : CoroutineWorker(context, params) {
    private val TAG = "MidnightPenaltyWorker"
    override suspend fun doWork(): Result {
        Timber.tag(TAG).d("MidnightPenaltyWorker started (backup)")
        val uid = auth.currentUser?.uid ?: run {
            Timber.tag(TAG).w("No authenticated user — skipping")
            return Result.success()
        }
        return try {
            val penalty = dailyResetManager.evaluateAndApply(uid)
            Timber.tag(TAG).i(
                if (penalty != null) "✔ Backup penalty applied → -${penalty.xpLost} XP"
                else "✔ No penalty needed (already applied on app open, or nothing to penalize)"
            )
            Result.success()
        } catch (e: Exception) {
            Timber.tag(TAG).e(e, "MidnightPenaltyWorker failed")
            Result.retry()
        }
    }
}



package com.gcancino.levelingup.data.workers
import android.content.Context
import androidx.hilt.work.HiltWorker
import androidx.work.CoroutineWorker
import androidx.work.WorkerParameters
import com.gcancino.levelingup.core.Resource
import com.gcancino.levelingup.data.repositories.DailyTasksRepositoryImpl
import com.gcancino.levelingup.domain.logic.DailyResetManager
import com.gcancino.levelingup.domain.repositories.BodyDataRepository
import com.gcancino.levelingup.domain.repositories.DailyTasksRepository
import com.gcancino.levelingup.domain.repositories.IdentityRepository
import com.google.firebase.auth.FirebaseAuth
import dagger.assisted.Assisted
import dagger.assisted.AssistedInject
import kotlinx.coroutines.coroutineScope
import kotlinx.coroutines.async
import kotlinx.coroutines.awaitAll
import timber.log.Timber
@HiltWorker
class NightlySyncWorker @AssistedInject constructor(
    @Assisted context: Context,
    @Assisted params: WorkerParameters,
    private val auth: FirebaseAuth,
    private val bodyDataRepository: BodyDataRepository,
    private val dailyTasksRepository: DailyTasksRepository,
    private val identityRepository: IdentityRepository,
    private val dailyResetManager: DailyResetManager
) : CoroutineWorker(context, params) {
    private val TAG = "NightlySyncWorker"
    override suspend fun doWork(): Result {
        Timber.tag(TAG).d("NightlySyncWorker started")
        val uid = auth.currentUser?.uid ?: run {
            Timber.tag(TAG).w("No authenticated user — skipping")
            return Result.success()
        }
        return try {
            coroutineScope {
                val resetJob = async {
                    try { dailyResetManager.evaluateAndApply(uid) }
                    catch (e: Exception) { Timber.tag(TAG).w("Reset failed: ${e.message}") }
                }
                val bodySync     = async { bodyDataRepository.syncUnsynced() }
                val dailySync    = async { dailyTasksRepository.syncUnsynced() }
                val identitySync = async { identityRepository.syncUnsynced() }
                resetJob.await()
                val results: List<Resource<*>> = awaitAll(bodySync, dailySync, identitySync)
                val error = results.filterIsInstance<Resource.Error<*>>().firstOrNull()
                if (error != null) {
                    Timber.tag(TAG).e("Sync failed: ${error.message}")
                    Result.retry()
                } else {
                    Timber.tag(TAG).i("✔ Nightly sync complete")
                    Result.success()
                }
            }
        } catch (e: Exception) {
            Timber.tag(TAG).e(e, "NightlySyncWorker failed")
            Result.retry()
        }
    }
}



package com.gcancino.levelingup.data.workers
import android.content.Context
import androidx.hilt.work.HiltWorker
import androidx.work.CoroutineWorker
import androidx.work.WorkerParameters
import com.gcancino.levelingup.data.local.database.dao.DailyStandardEntryDao
import com.gcancino.levelingup.data.local.database.dao.IdentityProfileDao
import com.gcancino.levelingup.data.local.database.dao.WeeklyReportDao
import com.gcancino.levelingup.data.local.database.entities.WeeklyReportEntity
import com.gcancino.levelingup.domain.logic.GeneratedQuestManager
import com.gcancino.levelingup.domain.models.identity.IdentityStandard
import com.gcancino.levelingup.domain.models.identity.Role
import com.google.firebase.auth.FirebaseAuth
import com.google.gson.Gson
import com.google.gson.reflect.TypeToken
import dagger.assisted.Assisted
import dagger.assisted.AssistedInject
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.withContext
import okhttp3.MediaType.Companion.toMediaType
import okhttp3.OkHttpClient
import okhttp3.Request
import okhttp3.RequestBody.Companion.toRequestBody
import org.json.JSONArray
import org.json.JSONObject
import timber.log.Timber
import java.time.DayOfWeek
import java.time.LocalDate
import java.time.ZoneId
import java.time.temporal.TemporalAdjusters
import java.util.*
import java.util.concurrent.TimeUnit
@HiltWorker
class WeeklySyncWorker @AssistedInject constructor(
    @Assisted context: Context,
    @Assisted params: WorkerParameters,
    private val auth: FirebaseAuth,
    private val identityProfileDao: IdentityProfileDao,
    private val standardEntryDao: DailyStandardEntryDao,
    private val weeklyReportDao: WeeklyReportDao,
    private val generatedQuestManager: GeneratedQuestManager
) : CoroutineWorker(context, params) {
    private val TAG = "WeeklySyncWorker"
    private val FLASK_BASE_URL = "https://leveling-up-server.vercel.app"
    private val gson = Gson()
    private val http = OkHttpClient.Builder()
        .connectTimeout(30, TimeUnit.SECONDS)
        .readTimeout(60, TimeUnit.SECONDS)
        .build()
    override suspend fun doWork(): Result = withContext(Dispatchers.IO) {
        Timber.tag(TAG).d("WeeklySyncWorker started")
        val uid = auth.currentUser?.uid ?: run {
            Timber.tag(TAG).w("No authenticated user")
            return@withContext Result.success()
        }
        return@withContext try {
            generateWeeklyReport(uid)
            Result.success()
        } catch (e: Exception) {
            Timber.tag(TAG).e(e, "Weekly report failed")
            Result.retry()
        }
    }
    private suspend fun generateWeeklyReport(uid: String) {
        val today     = LocalDate.now()
        val weekStart = today.with(TemporalAdjusters.previousOrSame(DayOfWeek.MONDAY))
        val weekEnd   = weekStart.plusDays(7)
        val startMs   = weekStart.atStartOfDay(ZoneId.systemDefault()).toInstant().toEpochMilli()
        val endMs     = weekEnd.atStartOfDay(ZoneId.systemDefault()).toInstant().toEpochMilli()
        if (weeklyReportDao.getForWeek(uid, startMs, endMs) != null) {
            Timber.tag(TAG).d("Report already exists for this week")
            return
        }
        val profileEntity = identityProfileDao.get(uid) ?: return
        val roles: List = gson.fromJson(profileEntity.roles,
            object : TypeToken<List>() {}.type)
        val standards: List = gson.fromJson(profileEntity.standards,
            object : TypeToken<List>() {}.type)
        val entries      = standardEntryDao.getForDay(uid, startMs, endMs)
        val entriesByDay = entries.groupBy {
            it.date.toInstant().atZone(ZoneId.systemDefault()).toLocalDate().toString()
        }
        val payload = JSONObject().apply {
            put("uid", uid)
            put("identity_statement", profileEntity.identityStatement)
            put("roles", JSONArray(roles.map { mapOf("id" to it.id, "name" to it.name) }
                .let { gson.toJson(it) }))
            put("standards", JSONArray(standards.map {
                mapOf("id" to it.id, "title" to it.title,
                    "type" to it.type.name, "role_id" to it.roleId)
            }.let { gson.toJson(it) }))
            val weekArray = JSONArray()
            entriesByDay.forEach { (date, dayEntries) ->
                weekArray.put(JSONObject().apply {
                    put("date", date)
                    put("standards_completed",
                        JSONArray(dayEntries.filter { it.isCompleted }.map { it.standardId }))
                    put("standards_total",
                        JSONArray(dayEntries.map { it.standardId }))
                    put("evening_answers", JSONArray())
                })
            }
            put("week_entries", weekArray)
        }
        val request = Request.Builder()
            .url("$FLASK_BASE_URL/identity/weekly-report")
            .post(payload.toString().toRequestBody("application/json".toMediaType()))
            .build()
        val response = http.newCall(request).execute()
        if (!response.isSuccessful) throw Exception("Flask error ${response.code}")
        val json = JSONObject(response.body.string())
        val reportId = UUID.randomUUID().toString()
        weeklyReportDao.insert(
            WeeklyReportEntity(
                id                = reportId,
                uID               = uid,
                weekStart         = Date(startMs),
                overallScore      = json.optDouble("overall_score", 0.0).toFloat(),
                headline          = json.optString("headline"),
                strongestRole     = json.optString("strongest_role"),
                weakestRole       = json.optString("weakest_role"),
                patternIdentified = json.optString("pattern_identified"),
                mirrorInsight     = json.optString("mirror_insight"),
                oneCorrection     = json.optString("one_correction"),
                identityAlignment = json.optString("identity_alignment"),
                generatedAt       = Date(),
                isSynced          = false
            )
        )
        Timber.tag(TAG).i("✔ Weekly report saved")
        val generatedQuestJson = json.optJSONObject("generated_quest")
        if (generatedQuestJson != null) {
            val questMap: Map = gson.fromJson(
                generatedQuestJson.toString(),
                object : TypeToken<Map>() {}.type
            )
            generatedQuestManager.saveQuestFromReport(uid, reportId, questMap)
        }
    }
}



package com.gcancino.levelingup.domain.logic
import android.content.SharedPreferences
import androidx.core.content.edit
import com.gcancino.levelingup.core.Resource
import com.gcancino.levelingup.data.local.database.dao.DailyStandardEntryDao
import com.gcancino.levelingup.data.local.database.dao.dailyTasks.DailyTaskDao
import com.gcancino.levelingup.data.local.database.dao.dailyTasks.PenaltyEventDao
import com.gcancino.levelingup.data.local.database.dao.PlayerProgressDao
import com.gcancino.levelingup.data.local.database.dao.PlayerStreakDao
import com.gcancino.levelingup.data.local.database.entities.dailyTasks.PenaltyEventEntity
import com.gcancino.levelingup.domain.models.dailyTasks.PenaltySummary
import com.google.gson.Gson
import timber.log.Timber
import java.time.LocalDate
import java.util.Date
import java.util.UUID
import javax.inject.Inject
import javax.inject.Singleton
@Singleton
class DailyResetManager @Inject constructor(
    private val timeProvider: TimeProvider,
    private val playerProgressDao: PlayerProgressDao,
    private val playerStreakDao: PlayerStreakDao,
    private val dailyTaskDao: DailyTaskDao,
    private val standardEntryDao: DailyStandardEntryDao,
    private val penaltyEventDao: PenaltyEventDao,
    private val generatedQuestManager: GeneratedQuestManager,
    private val prefs: SharedPreferences
) {
    private val TAG = "DailyResetManager"
    private val gson = Gson()
    companion object {
        private const val KEY_LAST_EVALUATED_DATE = "last_evaluated_date"
        private const val KEY_LAST_PENALTY_XP     = "last_penalty_xp_lost"
        private const val KEY_LAST_PENALTY_STREAK  = "last_penalty_streak_lost"
        private const val KEY_LAST_PENALTY_COUNT   = "last_penalty_tasks_count"
        private const val KEY_LAST_PENALTY_DATE    = "last_penalty_date"
    }
    suspend fun evaluateAndApply(uID: String): PenaltySummary? {
        val today         = timeProvider.today()
        val lastEvaluated = getLastEvaluatedDate()
        Timber.tag(TAG).d("evaluateAndApply() → today: $today | lastEvaluated: $lastEvaluated")
        if (lastEvaluated != null && lastEvaluated >= today.minusDays(1)) {
            Timber.tag(TAG).d("Already evaluated — skipping")
            return null
        }
        val startDay = lastEvaluated?.plusDays(1) ?: today.minusDays(1)
        val endDay   = today.minusDays(1)
        var totalXpLost    = 0
        var totalStreak    = 0
        var totalIncomplete = 0
        var day = startDay
        while (!day.isAfter(endDay)) {
            val result = evaluateDay(uID, day)
            if (result != null) {
                totalXpLost     += result.xpLost
                totalStreak      = result.streakLost
                totalIncomplete += result.incompleteTasks
            }
            day = day.plusDays(1)
        }
        markEvaluated(today.minusDays(1))
        if (totalXpLost > 0 || totalIncomplete > 0) {
            val summary = PenaltySummary(
                xpLost          = totalXpLost,
                streakLost      = totalStreak,
                incompleteTasks = totalIncomplete
            )
            savePenaltySummary(summary)
            Timber.tag(TAG).i(
                "✔ Penalties applied → XP: -$totalXpLost | " +
                        "streak reset | incomplete: $totalIncomplete"
            )
            return summary
        }
        return null
    }
    private suspend fun evaluateDay(uID: String, date: LocalDate): PenaltySummary? {
        val (start, end) = timeProvider.dayBoundaries(date)
        generatedQuestManager.evaluateProgress(uID)
        val incompleteStandards = standardEntryDao.getIncompleteForDay(uID, start, end)
        val incompleteTasks = dailyTaskDao.getIncompletePenaltyEligible(uID, start, end)
        val totalIncomplete = incompleteStandards.size + incompleteTasks.size
        if (totalIncomplete == 0) {
            Timber.tag(TAG).d("$date → clean, no penalty")
            return null
        }
        Timber.tag(TAG).d(
            "$date → $totalIncomplete incomplete " +
                    "(${incompleteStandards.size} standards + ${incompleteTasks.size} tasks)"
        )
        val xpFromStandards = incompleteStandards.sumOf { it.xpAwarded }
        val xpFromTasks     = incompleteTasks.sumOf { it.xpReward }
        val totalXpLost     = xpFromStandards + xpFromTasks
        val progress = playerProgressDao.getPlayerProgress(uID)
        if (progress != null && totalXpLost > 0) {
            val newXP    = maxOf(0, (progress.exp ?: 0) - totalXpLost)
            val newLevel = LevelCalculator.calculateLevel(newXP)
            playerProgressDao.updatePlayerProgress(progress.copy(exp = newXP, level = newLevel))
        }
        val streak     = playerStreakDao.getPlayerStreak(uID)
        val streakLost = streak?.currentStreak ?: 0
        if (streak != null && streakLost > 0) {
            playerStreakDao.updateStreak(uID, 0, Date())
        }
        incompleteStandards.forEach { standardEntryDao.markPenaltyApplied(it.id) }
        incompleteTasks.forEach    { dailyTaskDao.markPenaltyApplied(it.id) }
        val allIncompleteIds = incompleteStandards.map { it.id } + incompleteTasks.map { it.id }
        penaltyEventDao.insert(
            PenaltyEventEntity(
                id              = UUID.randomUUID().toString(),
                uID             = uID,
                date            = Date(start),
                xpLost          = totalXpLost,
                streakLost      = streakLost,
                incompleteTasks = gson.toJson(allIncompleteIds),
                isSynced        = false
            )
        )
        return PenaltySummary(
            xpLost          = totalXpLost,
            streakLost      = streakLost,
            incompleteTasks = totalIncomplete
        )
    }
    private fun getLastEvaluatedDate(): LocalDate? {
        val stored = prefs.getString(KEY_LAST_EVALUATED_DATE, null) ?: return null
        return try { LocalDate.parse(stored) } catch (e: Exception) { null }
    }
    private fun markEvaluated(date: LocalDate) {
        prefs.edit { putString(KEY_LAST_EVALUATED_DATE, date.toString()) }
    }
    private fun savePenaltySummary(summary: PenaltySummary) {
        prefs.edit {
            putInt(KEY_LAST_PENALTY_XP,     summary.xpLost)
            putInt(KEY_LAST_PENALTY_STREAK,  summary.streakLost)
            putInt(KEY_LAST_PENALTY_COUNT,   summary.incompleteTasks)
            putLong(KEY_LAST_PENALTY_DATE,   System.currentTimeMillis())
        }
    }
}



package com.gcancino.levelingup.domain.logic
import com.gcancino.levelingup.data.local.database.dao.DailyStandardEntryDao
import com.gcancino.levelingup.data.local.database.dao.GeneratedQuestDao
import com.gcancino.levelingup.data.local.database.dao.PlayerProgressDao
import com.gcancino.levelingup.data.local.database.entities.identity.GeneratedQuestEntity
import com.gcancino.levelingup.domain.models.identity.GeneratedQuestStatus
import com.gcancino.levelingup.domain.models.identity.GeneratedQuestType
import com.google.gson.Gson
import com.google.gson.reflect.TypeToken
import timber.log.Timber
import java.time.ZoneId
import java.util.Date
import java.util.UUID
import javax.inject.Inject
import javax.inject.Singleton
@Singleton
class GeneratedQuestManager @Inject constructor(
    private val questDao: GeneratedQuestDao,
    private val standardEntryDao: DailyStandardEntryDao,
    private val playerProgressDao: PlayerProgressDao,
    private val timeProvider: TimeProvider,
    private val gson: Gson
) {
    private val TAG = "GeneratedQuestManager"
    suspend fun saveQuestFromReport(
        uID: String,
        weeklyReportId: String,
        questJson: Map
    ) {
        try {
            val existing = questDao.getActive(uID)
            if (existing != null) {
                Timber.tag(TAG).d("Active quest already exists — skipping new quest creation")
                return
            }
            val title       = questJson["title"] as? String ?: return
            val description = questJson["description"] as? String ?: ""
            val typeStr     = questJson["type"] as? String ?: "CONSISTENCY"
            val targetIds   = (questJson["target_standard_ids"] as? List<*>)
                ?.filterIsInstance() ?: emptyList()
            val goal        = (questJson["goal"] as? Number)?.toInt() ?: 5
            val duration    = (questJson["duration_days"] as? Number)?.toInt() ?: 7
            val startDate = Date()
            val endDate   = Date(startDate.time + duration * 24 * 60 * 60 * 1000L)
            questDao.insert(
                GeneratedQuestEntity(
                    id                = UUID.randomUUID().toString(),
                    uID               = uID,
                    weeklyReportId    = weeklyReportId,
                    title             = title,
                    description       = description,
                    type              = typeStr,
                    targetStandardIds = gson.toJson(targetIds),
                    goal              = goal,
                    durationDays      = duration,
                    currentProgress   = 0,
                    status            = "ACTIVE",
                    startDate         = startDate,
                    endDate           = endDate,
                    xpReward          = 150,
                    isSynced          = false
                )
            )
            Timber.tag(TAG).i("✔ Generated quest saved → '$title' | type: $typeStr | $duration days")
        } catch (e: Exception) {
            Timber.tag(TAG).e(e, "saveQuestFromReport() failed")
        }
    }
    suspend fun evaluateProgress(uID: String) {
        val quest = questDao.getActive(uID) ?: return
        val today     = timeProvider.today()
        val yesterday = today.minusDays(1)
        val endDate = quest.endDate.toInstant().atZone(ZoneId.systemDefault()).toLocalDate()
        if (yesterday.isAfter(endDate)) {
            val finalStatus = if (quest.currentProgress >= quest.goal)
                GeneratedQuestStatus.COMPLETED else GeneratedQuestStatus.EXPIRED
            questDao.updateStatus(
                quest.id,
                finalStatus.name,
                if (finalStatus == GeneratedQuestStatus.COMPLETED) System.currentTimeMillis() else null
            )
            if (finalStatus == GeneratedQuestStatus.COMPLETED) {
                awardQuestXP(uID, quest.xpReward)
                Timber.tag(TAG).i("✔ Quest '${quest.title}' COMPLETED → +${quest.xpReward} XP")
            } else {
                Timber.tag(TAG).i("Quest '${quest.title}' EXPIRED (${quest.currentProgress}/${quest.goal})")
            }
            return
        }
        val targetIds: List = gson.fromJson(
            quest.targetStandardIds,
            object : TypeToken<List>() {}.type
        )
        val (start, end) = timeProvider.dayBoundaries(yesterday)
        val entries      = standardEntryDao.getForDay(uID, start, end)
            .filter { it.standardId in targetIds }
        val type    = GeneratedQuestType.valueOf(quest.type)
        val success = when (type) {
            GeneratedQuestType.STREAK       -> entries.all { it.isCompleted }
            GeneratedQuestType.CONSISTENCY  -> entries.any { it.isCompleted }
            GeneratedQuestType.ELIMINATION  -> entries.all { it.isCompleted }
        }
        if (success) {
            val newProgress = quest.currentProgress + 1
            questDao.updateProgress(quest.id, newProgress)
            Timber.tag(TAG).d("Quest progress → ${newProgress}/${quest.goal}")
            if (newProgress >= quest.goal) {
                questDao.updateStatus(
                    quest.id,
                    GeneratedQuestStatus.COMPLETED.name,
                    System.currentTimeMillis()
                )
                awardQuestXP(uID, quest.xpReward)
                Timber.tag(TAG).i("✔ Quest '${quest.title}' COMPLETED early → +${quest.xpReward} XP")
            }
        } else {
            if (type == GeneratedQuestType.STREAK) {
                questDao.updateProgress(quest.id, 0)
                Timber.tag(TAG).d("STREAK quest reset — missed yesterday")
            }
        }
    }
    private suspend fun awardQuestXP(uID: String, xp: Int) {
        val progress = playerProgressDao.getPlayerProgress(uID) ?: return
        val newXP    = (progress.exp ?: 0) + xp
        val newLevel = LevelCalculator.calculateLevel(newXP)
        playerProgressDao.updatePlayerProgress(progress.copy(exp = newXP, level = newLevel))
    }
}



package com.gcancino.levelingup.domain.logic
import kotlin.math.floor
import kotlin.math.sqrt
object LevelCalculator {
    private const val BASE_XP = 100.0
    private const val MAX_LEVEL = 100
    const val POINTS_PER_LEVEL = 5
    fun calculateLevel(totalXp: Int): Int {
        if (totalXp <= 0) return 1
        val level = floor(sqrt(totalXp / BASE_XP)).toInt() + 1
        return level.coerceAtMost(MAX_LEVEL)
    }
    fun xpRequiredForLevel(level: Int): Int {
        if (level <= 1) return 0
        return (BASE_XP * (level - 1) * (level - 1)).toInt()
    }
    fun calculateProgress(totalXp: Int): Float {
        val currentLevel = calculateLevel(totalXp)
        if (currentLevel >= MAX_LEVEL) return 1.0f
        val xpStartCurrent = xpRequiredForLevel(currentLevel)
        val xpStartNext = xpRequiredForLevel(currentLevel + 1)
        val xpInCurrentLevel = totalXp - xpStartCurrent
        val xpNeededForNextLevel = xpStartNext - xpStartCurrent
        return (xpInCurrentLevel.toFloat() / xpNeededForNextLevel.toFloat()).coerceIn(0f, 1f)
    }
    fun xpToNextLevel(totalXp: Int): Int {
        val currentLevel = calculateLevel(totalXp)
        if (currentLevel >= MAX_LEVEL) return 0
        val xpStartNext = xpRequiredForLevel(currentLevel + 1)
        return xpStartNext - totalXp
    }
}



package com.gcancino.levelingup.domain.logic
import java.time.LocalDate
import java.time.ZoneId
import javax.inject.Inject
import javax.inject.Singleton
interface TimeProvider {
    fun nowMillis(): Long
    fun today(): LocalDate
    fun yesterdayBoundaries(): Pair
    fun dayBoundaries(date: LocalDate): Pair
}
@Singleton
class RealTimeProvider @Inject constructor() : TimeProvider {
    override fun nowMillis(): Long = System.currentTimeMillis()
    override fun today(): LocalDate = LocalDate.now()
    override fun yesterdayBoundaries(): Pair =
        dayBoundaries(LocalDate.now().minusDays(1))
    override fun dayBoundaries(date: LocalDate): Pair {
        val zone  = ZoneId.systemDefault()
        val start = date.atStartOfDay(zone).toInstant().toEpochMilli()
        val end   = date.plusDays(1).atStartOfDay(zone).toInstant().toEpochMilli()
        return start to end
    }
}



