@Composable
fun TaskCreationStep(
    tasks: List,
    canAddMore: Boolean,
    onAddTask: (title: String, priority: TaskPriority) -> Unit,
    onRemoveTask: (String) -> Unit
) {
    var newTaskTitle by remember { mutableStateOf("") }
    var selectedPriority by remember { mutableStateOf(TaskPriority.LOW) }
    Column(
        modifier = Modifier
            .fillMaxWidth()
            .verticalScroll(rememberScrollState())
    ) {
        Text(
            "Tomorrow's Tasks",
            style      = MaterialTheme.typography.titleMedium,
            fontWeight = FontWeight.Bold,
            color      = Color.White
        )
        Text(
            "Focus on what matters. High priority tasks grant more XP.",
            style = MaterialTheme.typography.bodySmall,
            color = Color.Gray
        )
        Spacer(modifier = Modifier.height(16.dp))
        tasks.forEach { task ->
            TaskChip(task = task, onRemove = { onRemoveTask(task.id) })
            Spacer(modifier = Modifier.height(8.dp))
        }
        if (canAddMore) {
            Spacer(modifier = Modifier.height(8.dp))
            OutlinedTextField(
                value         = newTaskTitle,
                onValueChange = { newTaskTitle = it },
                label         = { Text("Task title") },
                modifier      = Modifier.fillMaxWidth(),
                singleLine    = true,
                colors        = OutlinedTextFieldDefaults.colors(
                    focusedBorderColor   = Color(0xFF7986CB),
                    unfocusedBorderColor = Color.DarkGray,
                    focusedTextColor     = Color.White,
                    unfocusedTextColor   = Color.White,
                    focusedLabelColor    = Color(0xFF7986CB),
                    unfocusedLabelColor  = Color.Gray,
                    cursorColor          = Color(0xFF7986CB)
                )
            )
            Spacer(modifier = Modifier.height(12.dp))
            Text("Priority", style = MaterialTheme.typography.bodySmall, color = Color.Gray)
            Spacer(modifier = Modifier.height(8.dp))
            Row(horizontalArrangement = Arrangement.spacedBy(8.dp)) {
                TaskPriority.entries.forEach { priority ->
                    FilterChip(
                        modifier = Modifier.weight(1f),
                        selected = selectedPriority == priority,
                        onClick  = { selectedPriority = priority },
                        label = {
                            Text(
                                "${priority.text}\n+${priority.xpReward} XP",
                                style = MaterialTheme.typography.labelSmall,
                                textAlign = TextAlign.Center,
                                modifier = Modifier.fillMaxWidth()
                            )
                        },
                        colors = FilterChipDefaults.filterChipColors(
                            selectedContainerColor = priority.color.copy(alpha = 0.2f),
                            selectedLabelColor = priority.color
                        )
                    )
                }
            }
            Spacer(modifier = Modifier.height(12.dp))
            Button(
                onClick  = {
                    if (newTaskTitle.isNotBlank()) {
                        onAddTask(newTaskTitle.trim(), selectedPriority)
                        newTaskTitle = ""
                        selectedPriority = TaskPriority.LOW
                    }
                },
                enabled  = newTaskTitle.isNotBlank(),
                modifier = Modifier.fillMaxWidth(),
                colors   = ButtonDefaults.buttonColors(containerColor = Color(0xFF7986CB))
            ) {
                Icon(Icons.Default.Add, contentDescription = null)
                Spacer(modifier = Modifier.width(8.dp))
                Text("Add Task")
            }
        } else {
            Spacer(modifier = Modifier.height(8.dp))
            Text(
                "Maximum 5 tasks reached",
                style = MaterialTheme.typography.bodySmall,
                color = Color.Gray
            )
        }
    }
}
@Preview
@Composable
fun SimpleTaskPreview() {
    val tasks: List = emptyList()
    TaskCreationStep(tasks, true, { _, _ -> }, {})
}



package com.gcancino.levelingup.presentation.player.dailyTasks.viewModels
import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import com.gcancino.levelingup.core.Resource
import com.gcancino.levelingup.data.local.datastore.DataStoreManager
import com.gcancino.levelingup.domain.models.Question
import com.gcancino.levelingup.domain.models.QuestionBank
import com.gcancino.levelingup.domain.models.dailyTasks.DailyTask
import com.gcancino.levelingup.domain.models.dailyTasks.EveningEntry
import com.gcancino.levelingup.domain.models.dailyTasks.ReflectionAnswer
import com.gcancino.levelingup.domain.models.dailyTasks.TaskPriority
import com.gcancino.levelingup.domain.models.dailyTasks.XPScale
import com.gcancino.levelingup.domain.repositories.DailyTasksRepository
import com.google.firebase.auth.FirebaseAuth
import dagger.hilt.android.lifecycle.HiltViewModel
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.SharingStarted
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.flow.combine
import kotlinx.coroutines.flow.map
import kotlinx.coroutines.flow.stateIn
import kotlinx.coroutines.launch
import timber.log.Timber
import java.util.Date
import java.util.UUID
import javax.inject.Inject
@HiltViewModel
class EveningFlowViewModel @Inject constructor(
    private val dailyRepository: DailyTasksRepository,
    private val dataStoreManager: DataStoreManager,
    private val auth: FirebaseAuth
) : ViewModel() {
    private val TAG = "EveningFlowViewModel"
    val questions: List = QuestionBank.getTodaysEveningQuestions()
    private val _answers = MutableStateFlow<Map>(emptyMap())
    val answers: StateFlow<Map> = _answers.asStateFlow()
    private val _tasks = MutableStateFlow<List>(emptyList())
    val tasks: StateFlow<List> = _tasks.asStateFlow()
    val currentStepIndex = MutableStateFlow(0)
    enum class EveningStep { QUESTIONS, TASKS }
    val currentPhase: EveningStep
        get() = if (currentStepIndex.value < questions.size) EveningStep.QUESTIONS
        else EveningStep.TASKS
    val totalSteps: Int get() = questions.size + 1
    private val _saveState = MutableStateFlow<Resource?>(null)
    val saveState: StateFlow<Resource?> = _saveState.asStateFlow()
    init {
        viewModelScope.launch {
            val draft = dataStoreManager.getEveningDraft()
            if (draft.isNotEmpty()) {
                _answers.value = draft
                currentStepIndex.value = draft.size.coerceAtMost(questions.size)
            }
        }
    }
    fun updateAnswer(questionId: String, answer: String) {
        _answers.value += (questionId to answer)
        viewModelScope.launch {
            dataStoreManager.saveEveningDraft(_answers.value)
        }
    }
    fun nextStep() {
        if (currentStepIndex.value < totalSteps - 1) currentStepIndex.value++
    }
    fun previousStep() {
        if (currentStepIndex.value > 0) currentStepIndex.value--
    }
    val isCurrentAnswerValid: StateFlow = combine(currentStepIndex, _answers) {
            index, currentAnswers ->
        val q = questions.getOrNull(index) ?: return@combine true
        val answerText = currentAnswers[q.id] ?: ""
        answerText.trim().length >= 10
    }.stateIn(
        scope = viewModelScope,
        started = SharingStarted.WhileSubscribed(5000),
        initialValue = false
    )
    val isLastStep: StateFlow = currentStepIndex
        .map { index -> index == totalSteps - 1 }
        .stateIn(
            scope = viewModelScope,
            started = SharingStarted.WhileSubscribed(5000),
            initialValue = false
        )
    fun addTask(title: String, priority: TaskPriority) {
        if (_tasks.value.size >= 5) return
        val uID = auth.currentUser?.uid ?: return
        val task = DailyTask(
            id = UUID.randomUUID().toString(),
            uID = uID,
            date = Date(),
            title = title,
            priority = priority,
            xpReward = XPScale.rewardForPriority(priority),
            isSynced = false
        )
        _tasks.value = (_tasks.value + task).sortedBy { it.priority }
    }
    fun removeTask(taskId: String) {
        _tasks.value = _tasks.value.filter { it.id != taskId }
    }
    fun reorderTask(taskId: String, newPriority: TaskPriority) {
        _tasks.value = _tasks.value.map { task ->
            if (task.id == taskId) task.copy(
                priority = newPriority,
                xpReward = XPScale.rewardForPriority(newPriority)
            ) else task
        }.sortedBy { it.priority }
    }
    val canAddMoreTasks: StateFlow = _tasks.map { it.size < 5 }
        .stateIn(viewModelScope, SharingStarted.WhileSubscribed(5000), true)
    fun save(questionTexts: Map) {
        val uID = auth.currentUser?.uid ?: run {
            _saveState.value = Resource.Error("Not authenticated"); return
        }
        viewModelScope.launch(Dispatchers.IO) {
            _saveState.value = Resource.Loading()
            val entry = EveningEntry(
                id = UUID.randomUUID().toString(),
                uID = uID,
                date = Date(),
                answers = questions.mapNotNull { q ->
                    _answers.value[q.id]?.let { answer ->
                        ReflectionAnswer(q.id, questionTexts[q.id] ?: "", answer)
                    }
                },
                isSynced = false
            )
            val entryResult = dailyRepository.saveEveningEntry(entry)
            val tasksResult = if (_tasks.value.isNotEmpty()) {
                dailyRepository.saveTasks(_tasks.value)
            } else Resource.Success(Unit)
            val finalResult = if (entryResult is Resource.Error) entryResult
                              else if (tasksResult is Resource.Error) tasksResult
                              else Resource.Success(Unit)
            _saveState.value = finalResult
            if (finalResult is Resource.Success) {
                dataStoreManager.clearEveningDraft()
                Timber.tag(TAG).i("✔ Evening entry + ${_tasks.value.size} task(s) saved")
            }
        }
    }
}



package com.gcancino.levelingup.presentation.player.dailyTasks.viewModels
import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import com.gcancino.levelingup.core.Resource
import com.gcancino.levelingup.data.local.datastore.DataStoreManager
import com.gcancino.levelingup.domain.models.Question
import com.gcancino.levelingup.domain.models.QuestionBank
import com.gcancino.levelingup.domain.models.dailyTasks.MorningEntry
import com.gcancino.levelingup.domain.models.dailyTasks.PenaltySummary
import com.gcancino.levelingup.domain.models.dailyTasks.ReflectionAnswer
import com.gcancino.levelingup.domain.use_cases.dailyTasks.SaveMorningEntryUseCase
import com.google.firebase.auth.FirebaseAuth
import dagger.hilt.android.lifecycle.HiltViewModel
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.SharingStarted
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.flow.combine
import kotlinx.coroutines.flow.map
import kotlinx.coroutines.flow.stateIn
import kotlinx.coroutines.launch
import timber.log.Timber
import java.util.Date
import java.util.UUID
import javax.inject.Inject
@HiltViewModel
class MorningFlowViewModel @Inject constructor(
    private val saveMorningEntryUseCase: SaveMorningEntryUseCase,
    private val auth: FirebaseAuth,
    private val dataStoreManager: DataStoreManager,
) : ViewModel() {
    private val TAG = "MorningFlowViewModel"
    val questions: List = QuestionBank.getTodaysMorningQuestions()
    private val _answers = MutableStateFlow<Map>(emptyMap())
    val answers: StateFlow<Map> = _answers.asStateFlow()
    val lastNightPenalty: StateFlow = dataStoreManager.userPreferences
        .map { prefs ->
            if (prefs.lastPenaltyXpLost > 0) {
                PenaltySummary(
                    xpLost = prefs.lastPenaltyXpLost,
                    streakLost = prefs.lastPenaltyStreakLost,
                    incompleteTasks = prefs.lastPenaltyTasksCount)
            } else null
        }.stateIn(viewModelScope, SharingStarted.WhileSubscribed(5000), null)
    val currentStepIndex = MutableStateFlow(0)
    val totalSteps: Int get() = questions.size
    private val _saveState = MutableStateFlow<Resource?>(null)
    val saveState: StateFlow<Resource?> = _saveState.asStateFlow()
    init {
        viewModelScope.launch {
            val draft = dataStoreManager.getMorningDraft()
            if (draft.isNotEmpty()) {
                _answers.value = draft
                currentStepIndex.value = (draft.size).coerceAtMost(questions.size)
            }
        }
    }
    fun updateAnswer(questionId: String, answer: String) {
        _answers.value += (questionId to answer)
        viewModelScope.launch {
            dataStoreManager.saveMorningDraft(_answers.value)
        }
    }
    fun nextStep() {
        if (currentStepIndex.value < totalSteps - 1) {
            currentStepIndex.value++
        }
    }
    fun previousStep() {
        if (currentStepIndex.value > 0) currentStepIndex.value--
    }
    val isCurrentAnswerValid: StateFlow = combine(currentStepIndex, _answers) {
        index, currentAnswers ->
            val q = questions.getOrNull(index) ?: return@combine false
            val answerText = currentAnswers[q.id] ?: ""
            answerText.trim().length >= 10
    }.stateIn(
        scope = viewModelScope,
        started = SharingStarted.WhileSubscribed(5000),
        initialValue = false
    )
    //val isLastStep: Boolean get() = currentStepIndex.value == totalSteps - 1
    val isLastStep: StateFlow = currentStepIndex
        .map { it == totalSteps - 1 }
        .stateIn(viewModelScope, SharingStarted.WhileSubscribed(5000), false)
    fun save(questionTexts: Map) {
        val uID = auth.currentUser?.uid ?: run {
            _saveState.value = Resource.Error("Not authenticated"); return
        }
        viewModelScope.launch(Dispatchers.IO) {
            _saveState.value = Resource.Loading()
            val entry = MorningEntry(
                id = UUID.randomUUID().toString(),
                uID = uID,
                date = Date(),
                answers = questions.mapNotNull { q ->
                    _answers.value[q.id]?.let { answer ->
                        ReflectionAnswer(q.id, questionTexts[q.id] ?: "", answer)
                    }
                },
                isSynced = false
            )
            // Use the Use Case!
            val result = saveMorningEntryUseCase(uID, entry)
            _saveState.value = result
            if (result is Resource.Success) {
                // Clear penalty prefs after showing and successful save
                dataStoreManager.clearPenalty()
                dataStoreManager.clearMorningDraft()
                Timber.tag(TAG).i("✔ Morning entry saved and XP awarded. New Level: ${result.data}")
            }
        }
    }
}



package com.gcancino.levelingup.presentation.player.dailyTasks
import androidx.compose.animation.AnimatedContent
import androidx.compose.animation.ExperimentalAnimationApi
import androidx.compose.animation.core.animateFloatAsState
