@HiltViewModel
class QuestMenuViewModel @Inject constructor(
    private val repository: QuestRepository
) : ViewModel() {
    private val _quests = MutableStateFlow<List>(emptyList())
    val quests: StateFlow<List> = _quests.asStateFlow()
    private val _updateQuestStatus = MutableStateFlow<Resource?>(null)
    val updateQuestStatus: StateFlow<Resource?> = _updateQuestStatus.asStateFlow()
    init {
        loadNotStartedQuests()
    }
    fun loadNotStartedQuests() {
        viewModelScope.launch {
            try {
                repository.getNotStartedQuests().collect { fetchedQuests ->
                    Timber.tag("QuestMenuViewModel").d("Fetched Quests: $fetchedQuests")
                    _quests.value = fetchedQuests
                }
            } catch (e: Exception) {
                _quests.value = emptyList()
            }
        }
    }
    fun updateQuestStatus(questID: String) {
        _updateQuestStatus.value = Resource.Loading()
        viewModelScope.launch {
            val result = repository.updateQuestStatus(questID)
            _updateQuestStatus.value = result
            if (result is Resource.Success) {
                Timber.tag("QuestMenuViewModel").d("Quest status updated successfully")
            } else {
                Timber.tag("QuestMenuViewModel").e("Failed to update quest status")
            }
        }
    }
    fun resetUpdateStatus() {
        _updateQuestStatus.value = null
    }
}



package com.gcancino.levelingup.presentation.player.dashboard.viewModels
import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import com.gcancino.levelingup.core.Resource
import com.gcancino.levelingup.domain.models.dailyTasks.DailyTask
import com.gcancino.levelingup.domain.models.dailyTasks.TaskPriority
import com.gcancino.levelingup.domain.models.dailyTasks.XPScale
import com.gcancino.levelingup.domain.repositories.DailyTasksRepository
import com.gcancino.levelingup.domain.repositories.PlayerRepository
import com.google.firebase.auth.FirebaseAuth
import dagger.hilt.android.lifecycle.HiltViewModel
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.flow.MutableSharedFlow
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.SharedFlow
import kotlinx.coroutines.flow.SharingStarted
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asSharedFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.flow.map
import kotlinx.coroutines.flow.stateIn
import kotlinx.coroutines.launch
import timber.log.Timber
import java.util.Date
import java.util.UUID
import javax.inject.Inject
@HiltViewModel
class TasksViewModel @Inject constructor(
    private val dailyRepository: DailyTasksRepository,
    private val playerRepository: PlayerRepository,
    private val auth: FirebaseAuth
) : ViewModel() {
    private val TAG = "TasksViewModel"
    private val uID get() = auth.currentUser?.uid ?: ""
    // Temporary list of tasks being created in the BottomSheet
    private val _tasks = MutableStateFlow<List>(emptyList())
    val tasks: StateFlow<List> = _tasks.asStateFlow()
    // Real-time observation of already saved tasks
    val allTasks: StateFlow<List> = dailyRepository
        .getTodaysTasks(uID)
        .stateIn(viewModelScope, SharingStarted.Eagerly, emptyList())
    val pendingTasks: StateFlow<List> = dailyRepository
        .getTodaysPendingTasks(uID)
        .stateIn(viewModelScope, SharingStarted.Eagerly, emptyList())
    val canAddMore: StateFlow = allTasks
        .map { it.size < 5 }
        .stateIn(viewModelScope, SharingStarted.Eagerly, true)
    // Events
    private val _xpEarned = MutableSharedFlow(replay = 0)
    val xpEarned: SharedFlow = _xpEarned.asSharedFlow()
    private val _levelUp = MutableSharedFlow(replay = 0)
    val levelUp: SharedFlow = _levelUp.asSharedFlow()
    private val _saveSuccess = MutableSharedFlow(replay = 0)
    val saveSuccess: SharedFlow = _saveSuccess.asSharedFlow()
    private val _error = MutableSharedFlow(replay = 0)
    val error: SharedFlow = _error.asSharedFlow()
    fun addTask(title: String, priority: TaskPriority) {
        val currentCount = _tasks.value.size + allTasks.value.size
        if (currentCount >= 5) return
        val uID = auth.currentUser?.uid ?: return
        val task = DailyTask(
            id = UUID.randomUUID().toString(),
            uID = uID,
            date = Date(),
            title = title,
            priority = priority,
            xpReward = XPScale.rewardForPriority(priority),
            isSynced = false
        )
        _tasks.value = (_tasks.value + task).sortedByDescending { it.priority }
    }
    fun removeTask(taskId: String) {
        _tasks.value = _tasks.value.filter { it.id != taskId }
    }
    fun saveTasks() {
        val tasksToSave = _tasks.value
        if (tasksToSave.isEmpty()) return
        viewModelScope.launch(Dispatchers.IO) {
            when (val result = dailyRepository.saveTasks(tasksToSave)) {
                is Resource.Success -> {
                    Timber.tag(TAG).i("✔ Tasks saved successfully")
                    _tasks.value = emptyList()
                    _saveSuccess.emit(Unit)
                }
                is Resource.Error -> {
                    val msg = result.message ?: "Failed to save tasks"
                    Timber.tag(TAG).e(msg)
                    _error.emit(msg)
                }
                else -> Unit
            }
        }
    }
    fun completeTask(taskId: String) {
        val task = allTasks.value.find { it.id == taskId }
        val reward = task?.xpReward ?: 0
        viewModelScope.launch(Dispatchers.IO) {
            when (val result = dailyRepository.completeTask(taskId, uID)) {
                is Resource.Success -> {
                    if (reward > 0) _xpEarned.emit(reward)
                    result.data?.let { newLevel ->
                        _levelUp.emit(newLevel)
                    }
                }
                is Resource.Error -> {
                    _error.emit(result.message ?: "Failed to complete task")
                }
                else -> Unit
            }
        }
    }
}



package com.gcancino.levelingup.presentation.player.dashboard
import androidx.compose.foundation.layout.*
