import com.gcancino.levelingup.ui.theme.BackgroundColor
import java.time.LocalDate
import com.gcancino.levelingup.ui.components.ExpandableFloatingButton
import com.gcancino.levelingup.ui.components.notifications.NotificationsViewModel
import com.gcancino.levelingup.ui.components.topBars.DashboardTopBar
import timber.log.Timber
@ExperimentalMaterial3Api
@Composable
fun DashboardScreen(
    viewModel: DashboardViewModel,
    bodyCompositionBottomSheetViewModel: BodyCompositionViewModel = hiltViewModel(),
    notificationViewModel: NotificationsViewModel = hiltViewModel(),
    tasksViewModel: TasksViewModel = hiltViewModel(),
    activeQuestViewModel: ActiveQuestViewModel = hiltViewModel(),
    identityViewModel: IdentityViewModel = hiltViewModel(),
    onStartSession: (LocalDate) -> Unit,
    onSetupIdentity: () -> Unit,
    onViewStandards: () -> Unit,
    onProfileClick: () -> Unit,
    onStartMorningFlow: () -> Unit,
    onStartEveningFlow: () -> Unit,
) {
    val syncState by viewModel.syncState.collectAsState()
    val calendarViewModel: CalendarViewmodel = viewModel()
    val selectedDate by calendarViewModel.selectedDate.collectAsState()
    val todaySessionState by viewModel.todaySession.collectAsState()
    val notifications by notificationViewModel.notifications.collectAsState()
    val notificationCount by notificationViewModel.notificationCount.collectAsState()
    val snackbarHostState: SnackbarHostState = remember { SnackbarHostState() }
    var isNotificationExpanded by remember { mutableStateOf(false) }
    val scrollState = rememberScrollState()
    val sheetState = rememberModalBottomSheetState(skipPartiallyExpanded = true)
    var showBodyCompositionSheet by remember { mutableStateOf(false) }
    val showTaskCreationSheet by viewModel.showTaskCreationSheet.collectAsState()
    val tasks by tasksViewModel.tasks.collectAsState()
    val canAddMore by tasksViewModel.canAddMore.collectAsState()
    LaunchedEffect(Unit) {
        tasksViewModel.saveSuccess.collect {
            viewModel.closeTaskCreation()
            snackbarHostState.showSnackbar("Daily tasks updated!")
        }
    }
    LaunchedEffect(Unit) {
        tasksViewModel.error.collect { message ->
            snackbarHostState.showSnackbar(message)
        }
    }
    if (showBodyCompositionSheet) {
        BodyCompositionBottomSheet (
            viewModel = bodyCompositionBottomSheetViewModel,
            onDismiss = {
                showBodyCompositionSheet = false
                notificationViewModel.refresh()
            },
            snackbarState = snackbarHostState
        )
    }
    if (showTaskCreationSheet) {
        ModalBottomSheet(
            onDismissRequest = { viewModel.closeTaskCreation() },
            sheetState = sheetState,
            containerColor = Color(0xFF0A0A0A),
            scrimColor = Color.Black.copy(alpha = 0.7f)
        ) {
            Box(modifier = Modifier.padding(bottom = 32.dp, start = 16.dp, end = 16.dp)) {
                TaskCreationBottomSheet (
                    tasks = tasks,
                    canAddMore = canAddMore,
                    onAddTask = { title, priority ->
                        tasksViewModel.addTask(title, priority)
                    },
                    onRemoveTask = { id -> tasksViewModel.removeTask(id) },
                    onSave = { tasksViewModel.saveTasks() }
                )
            }
        }
    }
    val showMorningCTA by viewModel.showMorningCTA.collectAsState()
    val showEveningCTA by viewModel.showEveningCTA.collectAsState()
    LaunchedEffect(syncState) {
        when (syncState) {
            is SyncState.Syncing -> Timber.tag("DashboardScreen").d("Syncing week data...")
            is SyncState.Success -> Timber.tag("DashboardScreen").d("Sync complete")
            is SyncState.Error   -> Timber.tag("DashboardScreen").e("Sync error: ${(syncState as SyncState.Error).message}")
            is SyncState.Idle    -> Unit
        }
    }
    LaunchedEffect(selectedDate) {
        viewModel.getSessionForDate(selectedDate)
    }
    Scaffold(
        modifier = Modifier.fillMaxSize(),
        containerColor = BackgroundColor,
        snackbarHost = { SnackbarHost(hostState = snackbarHostState) },
        topBar         = {
            DashboardTopBar(
                onProfileClick = onProfileClick,
                notificationCount = notificationCount,
                notificationsExpanded = isNotificationExpanded,
                onNotificationsBellClick = { isNotificationExpanded = true },
                onNotificationsDismiss = { isNotificationExpanded = false },
                notifications            = notifications,
                onNotificationTapped     = { notification ->
                    when (notification.type) {
                        NotificationType.MISSING_INITIAL_MEASUREMENTS,
                        NotificationType.MISSING_INITIAL_COMPOSITION -> {
                            showBodyCompositionSheet = true
                        }
                        else -> notification.action?.invoke()
                    }
                }
            )
        },
        floatingActionButton = {
            ExpandableFloatingButton(
                snackbarState = snackbarHostState,
                bodyCompositionViewModel = bodyCompositionBottomSheetViewModel,
            )
        }
    ) { innerPadding ->
        Column(
            modifier = Modifier
                .fillMaxSize()
                .padding(innerPadding)
                .padding(top = 16.dp)
        ) {
            WeeklyCalendar(viewModel = calendarViewModel)
            Spacer(modifier = Modifier.height(16.dp))
            Column(
                modifier = Modifier
                    .fillMaxWidth()
                    .verticalScroll(scrollState)
                    .weight(1f)
            ) {
                if (syncState is SyncState.Syncing) {
                    LinearProgressIndicator(
                        modifier = Modifier.fillMaxWidth(),
                        color    = MaterialTheme.colorScheme.primary
                    )
                    Spacer(modifier = Modifier.height(8.dp))
                }
                if (showMorningCTA) {
                    DailyFlowCTACard(
                        title    = "Morning Reflection 🌅",
                        subtitle = "Start your day with intention",
                        color    = Color(0xFFFFB300),
                        onClick  = onStartMorningFlow
                    )
                    Spacer(modifier = Modifier.height(8.dp))
                }
                if (showEveningCTA) {
                    DailyFlowCTACard(
                        title    = "Evening Reflection 🌙",
                        subtitle = "Review your day and set tomorrow's tasks",
                        color    = Color(0xFF7986CB),
                        onClick  = onStartEveningFlow
                    )
                    Spacer(modifier = Modifier.height(4.dp))
                }
                when (val resource = todaySessionState) {
                    is Resource.Loading -> {
                        Box(
                            modifier = Modifier
                                .fillMaxWidth()
                                .height(200.dp),
                            contentAlignment = Alignment.Center
                        ) {
                            CircularProgressIndicator(color = MaterialTheme.colorScheme.primary)
                        }
                    }
                    is Resource.Success -> {
                        TodaySessionCard(
                            session = resource.data,
                            isToday = selectedDate == LocalDate.now(),
                            onStartSession = { onStartSession(selectedDate) }
                        )
                    }
                    is Resource.Error -> {
                        Text(
                            text = "Error: ${resource.message}",
                            modifier = Modifier.padding(16.dp),
                            color = MaterialTheme.colorScheme.error
                        )
                    }
                }
                Spacer(modifier = Modifier.height(2.dp))
                IdentityCard(
                    viewModel = identityViewModel,
                    onViewStandards = onViewStandards,
                    onSetupIdentity = onSetupIdentity
                )
                Spacer(modifier = Modifier.height(4.dp))
                ActiveQuestCard(
                    viewModel = activeQuestViewModel
                )
            }
        }
    }
}



package com.gcancino.levelingup.presentation.player.dashboard
import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import com.gcancino.levelingup.core.Resource
import com.gcancino.levelingup.core.SyncState
import com.gcancino.levelingup.data.repositories.DailyTasksRepositoryImpl
import com.gcancino.levelingup.domain.models.dailyTasks.DailyTask
import com.gcancino.levelingup.domain.models.dailyTasks.TaskPriority
import com.gcancino.levelingup.domain.models.dailyTasks.XPScale
import com.gcancino.levelingup.domain.models.exercise.TrainingSession
import com.gcancino.levelingup.domain.repositories.ExerciseRepository
import com.google.firebase.auth.FirebaseAuth
import dagger.hilt.android.lifecycle.HiltViewModel
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.SharingStarted
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.flow.combine
import kotlinx.coroutines.flow.flow
import kotlinx.coroutines.flow.flowOn
import kotlinx.coroutines.flow.map
import kotlinx.coroutines.flow.stateIn
import kotlinx.coroutines.launch
import timber.log.Timber
import java.time.LocalDate
import java.time.LocalDateTime
import java.time.ZoneId
import java.util.Calendar
import java.util.Date
import java.util.UUID
import javax.inject.Inject
@HiltViewModel
class DashboardViewModel @Inject constructor(
    private val exerciseRepository: ExerciseRepository,
    dailyTasksRepository: DailyTasksRepositoryImpl,
    private val auth: FirebaseAuth
) : ViewModel() {
    private val TAG = "DashboardViewModel"
    val uID = auth.currentUser?.uid ?: ""
    // Sync State
    private val _syncState = MutableStateFlow(SyncState.Idle)
    val syncState: StateFlow = _syncState.asStateFlow()
    // Session State
    private val _todaySession = MutableStateFlow<Resource>(Resource.Loading())
    val todaySession: StateFlow<Resource> = _todaySession.asStateFlow()
    // Time Window for Daily Tasks
    private val currentHour = LocalDateTime.now().hour
    private val morningWindowOpen = currentHour in 5..11
    private val eveningWindowOpen = currentHour in 21..23
    private val hasDoneMorning = dailyTasksRepository.observeMorningCompletedToday(uID)
    private val hasDoneEvening = dailyTasksRepository.observeEveningCompletedToday(uID)
    val showMorningCTA: StateFlow = hasDoneMorning
        .map { done -> morningWindowOpen && !done }
        .stateIn(viewModelScope, SharingStarted.Eagerly, false)
    val showEveningCTA: StateFlow = hasDoneEvening
        .map { done -> eveningWindowOpen && !done }
        .stateIn(viewModelScope, SharingStarted.Eagerly, false)
    private val _showTaskCreationSheet = MutableStateFlow(false)
    val showTaskCreationSheet: StateFlow = _showTaskCreationSheet.asStateFlow()
    init {
        Timber.tag(TAG).d("ViewModel initialized. Starting week sync...")
        syncAndLoad()
    }
    /**
     * Runs sync on Dispatchers.IO to avoid blocking the main thread.
     * Once sync finishes, loads today's session from Room.
     */
    private fun syncAndLoad() {
        viewModelScope.launch(Dispatchers.IO) {
            _syncState.value = SyncState.Syncing
            Timber.tag(TAG).d("Sync state → Syncing (thread: ${Thread.currentThread().name})")
            when (val syncResult = exerciseRepository.syncWeek(LocalDate.now())) {
                is Resource.Success -> {
                    Timber.tag(TAG).i("Sync succeeded. Loading today's session from Room.")
                    _syncState.value = SyncState.Success
                    loadSessionForDate(LocalDate.now())
                }
                is Resource.Error -> {
                    Timber.tag(TAG).e("Sync failed: ${syncResult.message}. Attempting local load anyway.")
                    _syncState.value = SyncState.Error(syncResult.message ?: "Sync failed")
                    loadSessionForDate(LocalDate.now())
                }
                is Resource.Loading -> {  }
            }
        }
    }
    fun getSessionForDate(localDate: LocalDate) {
        viewModelScope.launch(Dispatchers.IO) {
            Timber.tag(TAG).d("getSessionForDate() called for: $localDate")
            loadSessionForDate(localDate)
        }
    }
    private suspend fun loadSessionForDate(localDate: LocalDate) {
        val date = Date.from(
            localDate.atStartOfDay(ZoneId.systemDefault()).toInstant()
        )
        Timber.tag(TAG).d("Loading session from Room for date: $date")
        exerciseRepository.getSessionForDate(date)
            .flowOn(Dispatchers.IO)
            .collect { resource ->
                _todaySession.value = resource
                when (resource) {
                    is Resource.Success ->
                        Timber.tag(TAG).i(
                            "Session loaded → %s", if (resource.data != null)
                                        "id: ${resource.data.id}, name: ${resource.data.name}"
                                    else "no session (Rest Day)"
                        )
                    is Resource.Error ->
                        Timber.tag(TAG).d("Failed to load session: ${resource.message}")
                    is Resource.Loading ->
                        Timber.tag(TAG).d("Loading session...")
                }
            }
    }
    fun openTaskCreation() { _showTaskCreationSheet.value = true }
    fun closeTaskCreation() { _showTaskCreationSheet.value = false }
    fun refresh() {
        Timber.tag(TAG).d("Manual refresh triggered.")
        syncAndLoad()
    }
}



package com.gcancino.levelingup.presentation.player.identity
import androidx.compose.animation.core.animateFloatAsState
import androidx.compose.animation.core.tween
import androidx.compose.foundation.background
import androidx.compose.foundation.layout.*
import androidx.compose.foundation.shape.CircleShape
import androidx.compose.foundation.shape.RoundedCornerShape
import androidx.compose.material3.*
import androidx.compose.runtime.*
import androidx.compose.ui.Alignment
import androidx.compose.ui.Modifier
import androidx.compose.ui.draw.clip
import androidx.compose.ui.graphics.Color
import androidx.compose.ui.text.font.FontWeight
import androidx.compose.ui.unit.dp
import androidx.compose.ui.unit.sp
import androidx.hilt.lifecycle.viewmodel.compose.hiltViewModel
import com.gcancino.levelingup.domain.models.identity.GeneratedQuestType
@Composable
fun ActiveQuestCard(
    modifier: Modifier = Modifier,
    viewModel: ActiveQuestViewModel = hiltViewModel()
) {
    val quest by viewModel.activeQuest.collectAsState()
    quest ?: return
    val q         = quest!!
    val progress  = q.currentProgress.toFloat() / q.goal.toFloat()
    val questType = try { GeneratedQuestType.valueOf(q.type) } catch (e: Exception) { GeneratedQuestType.CONSISTENCY }
    val typeColor = when (questType) {
        GeneratedQuestType.STREAK      -> Color(0xFFFFD740)
        GeneratedQuestType.CONSISTENCY -> Color(0xFF7986CB)
        GeneratedQuestType.ELIMINATION -> Color(0xFF00E676)
    }
    val typeIcon = when (questType) {
        GeneratedQuestType.STREAK      -> "🔥"
        GeneratedQuestType.CONSISTENCY -> "📊"
        GeneratedQuestType.ELIMINATION -> "🎯"
    }
    val animatedProgress by animateFloatAsState(
        targetValue   = progress.coerceIn(0f, 1f),
        animationSpec = tween(800),
        label         = "questProgress"
    )
    Card(
        modifier = modifier
            .fillMaxWidth()
            .padding(horizontal = 16.dp, vertical = 4.dp),
        shape  = RoundedCornerShape(24.dp),
        colors = CardDefaults.cardColors(
            containerColor = typeColor.copy(alpha = 0.08f)
        ),
        border = androidx.compose.foundation.BorderStroke(
            1.dp, typeColor.copy(alpha = 0.3f)
        )
    ) {
        Column(modifier = Modifier.fillMaxWidth().padding(20.dp)) {
            Row(
                modifier              = Modifier.fillMaxWidth(),
                horizontalArrangement = Arrangement.SpaceBetween,
                verticalAlignment     = Alignment.Top
            ) {
                Column(modifier = Modifier.weight(1f)) {
                    Row(verticalAlignment = Alignment.CenterVertically) {
                        Text(typeIcon, style = MaterialTheme.typography.bodyMedium)
                        Spacer(modifier = Modifier.width(6.dp))
                        Text(
                            "CORRECTIVE QUEST",
                            style         = MaterialTheme.typography.labelSmall,
                            color         = typeColor,
                            fontWeight    = FontWeight.Bold,
                            letterSpacing = 1.sp
                        )
                    }
                    Spacer(modifier = Modifier.height(4.dp))
                    Text(
                        q.title,
                        style      = MaterialTheme.typography.titleMedium,
                        fontWeight = FontWeight.ExtraBold,
                        color      = Color.White
                    )
                }
                Box(
                    modifier         = Modifier
                        .size(52.dp)
                        .background(typeColor.copy(alpha = 0.15f), CircleShape),
                    contentAlignment = Alignment.Center
                ) {
                    Text(
                        "${q.currentProgress}/${q.goal}",
                        style      = MaterialTheme.typography.labelLarge,
                        fontWeight = FontWeight.ExtraBold,
                        color      = typeColor
                    )
                }
            }
            Spacer(modifier = Modifier.height(4.dp))
            Text(
                q.description,
                style   = MaterialTheme.typography.bodySmall,
                color   = Color.Gray,
                maxLines = 2
            )
            Spacer(modifier = Modifier.height(12.dp))
            LinearProgressIndicator(
                progress   = { animatedProgress },
                modifier   = Modifier.fillMaxWidth().height(6.dp).clip(CircleShape),
                color      = typeColor,
                trackColor = Color(0xFF2C2C2E)
            )
            Spacer(modifier = Modifier.height(6.dp))
            val daysLeft = try {
                val end   = q.endDate.toInstant()
                    .atZone(java.time.ZoneId.systemDefault()).toLocalDate()
                val today = java.time.LocalDate.now()
                java.time.temporal.ChronoUnit.DAYS.between(today, end).toInt().coerceAtLeast(0)
            } catch (e: Exception) { 0 }
            Text(
                "$daysLeft day${if (daysLeft != 1) "s" else ""} remaining · +${q.xpReward} XP on completion",
                style = MaterialTheme.typography.labelSmall,
                color = Color.Gray
            )
        }
    }
}



