import timber.log.Timber
@ExperimentalMaterial3Api
@Composable
fun ProfileScreen(
    viewModel: ProfileViewModel = hiltViewModel(),
    onNavigateToIdentityWall: () -> Unit,
    onNavigateBack: () -> Unit,
    onSignOut: () -> Unit
) {
    val playerDataState by viewModel.playerData.collectAsState()
    val scrollState = rememberScrollState()
    Scaffold(
        topBar = {
            TopAppBar(
                title = { Text("Profile", fontWeight = FontWeight.Bold) },
                navigationIcon = {
                    IconButton(onClick = onNavigateBack) {
                        Icon(Icons.AutoMirrored.Filled.ArrowBack, contentDescription = "Back")
                    }
                },
                actions = {
                    IconButton(onClick = {}) {
                        Icon(Icons.Outlined.Sync, contentDescription = "Sync")
                    }
                    IconButton(onClick = { onNavigateToIdentityWall() }) {
                        Icon(Icons.Default.Psychology, contentDescription = "Identity Wall")
                    }
                    IconButton(onClick = { viewModel.signOut(onSignOut) }) {
                        Icon(painter = painterResource(R.drawable.logout), contentDescription = "Sign out")
                    }
                    IconButton(onClick = {  }) {
                        Icon(Icons.Default.Settings, contentDescription = "Settings")
                    }
                },
                colors = TopAppBarDefaults.topAppBarColors(
                    containerColor = BackgroundColor,
                    titleContentColor = Color.White,
                    navigationIconContentColor = Color.White,
                    actionIconContentColor = Color.White
                )
            )
        },
        containerColor = BackgroundColor
    ) { padding ->
        Box(
            modifier = Modifier
                .fillMaxSize()
                .padding(padding)
        ) {
            when (val resource = playerDataState) {
                is Resource.Loading -> {
                    CircularProgressIndicator(
                        modifier = Modifier.align(Alignment.Center),
                        color = MaterialTheme.colorScheme.primary
                    )
                }
                is Resource.Success -> {
                    val data = resource.data
                    if (data != null) {
                        Timber.tag("PlayerScreen").d("PlayerData: $data")
                        ProfileContent(
                            data = data,
                            scrollState = scrollState,
                        )
                    }
                }
                is Resource.Error -> {
                    Text(
                        text = resource.message ?: "Error loading profile",
                        color = MaterialTheme.colorScheme.error,
                        modifier = Modifier.align(Alignment.Center)
                    )
                }
            }
        }
    }
}
@Composable
private fun ProfileContent(
    data: PlayerData,
    scrollState: androidx.compose.foundation.ScrollState,
) {
    Timber.d("PlayerData: player=${data.player}, attributes=${data.attributes}")
    Column(
        modifier = Modifier
            .fillMaxSize()
            .verticalScroll(scrollState)
            .padding(24.dp),
        horizontalAlignment = Alignment.CenterHorizontally
    ) {
        Box(contentAlignment = Alignment.BottomEnd) {
            Surface(
                modifier = Modifier.size(120.dp),
                shape = CircleShape,
                color = Color(0xFF2C2C2E)
            ) {
                if (data.player?.photoURL != null) {
                    AsyncImage(
                        model = data.player.photoURL,
                        contentDescription = null,
                        contentScale = ContentScale.Crop,
                        modifier = Modifier.clip(CircleShape)
                    )
                } else {
                    Box(contentAlignment = Alignment.Center) {
                        Text(
                            text = data.player?.displayName?.firstOrNull()?.uppercase() ?: "P",
                            style = MaterialTheme.typography.displayMedium,
                            color = MaterialTheme.colorScheme.primary,
                            fontWeight = FontWeight.Black
                        )
                    }
                }
            }
            FloatingActionButton(
                onClick = {  },
                modifier = Modifier.size(36.dp),
                shape = CircleShape,
                containerColor = MaterialTheme.colorScheme.primary,
                contentColor = Color.Black
            ) {
                Icon(Icons.Default.Edit, contentDescription = null, modifier = Modifier.size(18.dp))
            }
        }
        Spacer(modifier = Modifier.height(4.dp))
        Text(
            text = data.player?.displayName ?: "Player Name",
            style = MaterialTheme.typography.headlineMedium,
            fontWeight = FontWeight.Bold,
            color = Color.White
        )
        Spacer(modifier = Modifier.height(8.dp))
        Card(
            modifier = Modifier.fillMaxWidth(),
            shape = RoundedCornerShape(24.dp),
            colors = CardDefaults.cardColors(containerColor = Color(0xFF1C1C1E))
        ) {
            val totalXp = data.progress?.exp ?: 0
            val currentLevel = LevelCalculator.calculateLevel(totalXp)
            val progress = LevelCalculator.calculateProgress(totalXp)
            val xpToNext = LevelCalculator.xpToNextLevel(totalXp)
            val nextLevelXp = LevelCalculator.xpRequiredForLevel(currentLevel + 1)
            Column(modifier = Modifier.padding(20.dp)) {
                Row(
                    modifier = Modifier.fillMaxWidth(),
                    horizontalArrangement = Arrangement.SpaceBetween,
                    verticalAlignment = Alignment.CenterVertically
                ) {
                    Text(
                        "Level $currentLevel",
                        style = MaterialTheme.typography.titleLarge,
                        fontWeight = FontWeight.Bold,
                        color = Color.White
                    )
                    Text(
                        "$totalXp / $nextLevelXp XP",
                        style = MaterialTheme.typography.labelLarge,
                        color = MaterialTheme.colorScheme.primary
                    )
                }
                Spacer(modifier = Modifier.height(12.dp))
                LinearProgressIndicator(
                    progress = { progress },
                    modifier = Modifier
                        .fillMaxWidth()
                        .height(8.dp)
                        .clip(CircleShape),
                    color = MaterialTheme.colorScheme.primary,
                    trackColor = Color(0xFF2C2C2E)
                )
                if (currentLevel < 100) {
                    Spacer(modifier = Modifier.height(8.dp))
                    Text(
                        text = "$xpToNext XP until next level",
                        style = MaterialTheme.typography.labelSmall,
                        color = Color.Gray,
                        modifier = Modifier.align(Alignment.End)
                    )
                }
            }
        }
        Spacer(modifier = Modifier.height(24.dp))
        data.attributes?.let { attributes ->
            StatsCard(attributes = attributes)
        }
        Spacer(modifier = Modifier.height(32.dp))
    }
}



package com.gcancino.levelingup.presentation.player.profile
import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import com.gcancino.levelingup.core.Resource
import com.gcancino.levelingup.data.repositories.AuthRepositoryImpl
import com.gcancino.levelingup.data.repositories.PlayerRepositoryImpl
import com.gcancino.levelingup.domain.models.player.PlayerData
import com.gcancino.levelingup.domain.repositories.AuthRepository
import dagger.hilt.android.lifecycle.HiltViewModel
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.launch
import timber.log.Timber
import javax.inject.Inject
@HiltViewModel
class ProfileViewModel @Inject constructor(
    private val authRepository: AuthRepositoryImpl,
    private val playerRepository: PlayerRepositoryImpl
) : ViewModel() {
    private val _playerData = MutableStateFlow<Resource>(Resource.Loading())
    val playerData: StateFlow<Resource> = _playerData.asStateFlow()
    init {
        loadProfile()
    }
    fun loadProfile() {
        viewModelScope.launch {
            playerRepository.getPlayerData().collect { resource ->
                _playerData.value = resource
                if (resource is Resource.Success && resource.data != null) {
                    val data = resource.data
                    if (data.attributes == null || data.progress == null || data.streak == null) {
                        syncMissingData(data.player?.uid)
                    }
                }
            }
        }
    }
    private fun syncMissingData(uid: String?) {
        if (uid == null) return
        viewModelScope.launch {
            val result = playerRepository.syncMissingData(uid)
            if (result is Resource.Success) {
                loadProfile()
            } else {
                Timber.e("Sync failed: ${result.message}")
            }
        }
    }
    fun signOut(onSuccess: () -> Unit) {
        viewModelScope.launch {
            val result = authRepository.signOut()
            if (result is Resource.Success) {
                onSuccess()
            }
        }
    }
}



package com.gcancino.levelingup.presentation.player.profile
import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import com.gcancino.levelingup.core.Resource
import com.gcancino.levelingup.core.SyncState
import com.gcancino.levelingup.domain.repositories.BodyDataRepository
import com.gcancino.levelingup.domain.repositories.DailyTasksRepository
import com.gcancino.levelingup.domain.repositories.IdentityRepository
import com.google.firebase.auth.FirebaseAuth
import dagger.hilt.android.lifecycle.HiltViewModel
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.async
import kotlinx.coroutines.awaitAll
import kotlinx.coroutines.delay
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.launch
import javax.inject.Inject
@HiltViewModel
class SyncViewModel @Inject constructor(
    private val bodyDataRepository: BodyDataRepository,
    private val dailyTasksRepository: DailyTasksRepository,
    private val identityRepository: IdentityRepository,
    private val auth: FirebaseAuth
) : ViewModel() {
    private val _syncState = MutableStateFlow(SyncState.Idle)
    val syncState: StateFlow = _syncState.asStateFlow()
    fun syncAll() {
        val uid = auth.currentUser?.uid ?: return
        viewModelScope.launch(Dispatchers.IO) {
            _syncState.value = SyncState.Syncing
            val results = listOf(
                async { bodyDataRepository.syncUnsynced() },
                async { dailyTasksRepository.syncUnsynced() },
                async { identityRepository.syncUnsynced() }
            ).awaitAll()
            val error = results.filterIsInstance<Resource.Error<*>>().firstOrNull()
            _syncState.value = if (error != null) {
                SyncState.Error(error.message ?: "Sync failed")
            } else {
                SyncState.Success
            }
            if (_syncState.value is SyncState.Success) {
                delay(3000)
                _syncState.value = SyncState.Idle
            }
        }
    }
}



