@OptIn(ExperimentalMaterial3Api::class)
@ExperimentalAnimationApi
@ExperimentalFoundationApi
@Composable
fun SessionPlayerScreen(
    viewModel: SessionPlayerViewModel = hiltViewModel(),
    onNavigateBack: () -> Unit
) {
    val sessionState        by viewModel.session.collectAsState()
    val completedCount      by viewModel.completedSetsCount.collectAsState()
    val totalCount          by viewModel.totalSetsCount.collectAsState()
    val isSessionComplete   by viewModel.isSessionComplete.collectAsState()
    var showNotificationRationale by remember { mutableStateOf(false) }
    var pendingPermissionRequest  by remember { mutableStateOf(false) }
    val hasRequestedPermission by viewModel.hasRequestedPermission.collectAsState()
    val permissionLauncher = rememberLauncherForActivityResult(
        contract = ActivityResultContracts.RequestPermission()
    ) { isGranted ->
        Timber.tag("SessionPlayerScreen").d("Notification permission: $isGranted")
    }
    LaunchedEffect(pendingPermissionRequest) {
        if (pendingPermissionRequest) {
            pendingPermissionRequest = false
            if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.TIRAMISU) {
                permissionLauncher.launch(Manifest.permission.POST_NOTIFICATIONS)
            }
        }
    }
    if (showNotificationRationale) {
        AlertDialog(
            onDismissRequest  = { showNotificationRationale = false },
            containerColor    = Color(0xFF1C1C1E),
            titleContentColor = Color.White,
            textContentColor  = Color.Gray,
            icon = {
                Icon(
                    Icons.Default.Timer,
                    contentDescription = null,
                    tint     = MaterialTheme.colorScheme.primary,
                    modifier = Modifier.size(32.dp)
                )
            },
            title = { Text("Enable Rest Timer Alerts", fontWeight = FontWeight.Bold) },
            text  = {
                Text("Get notified when your rest period ends so you never miss a set, even when the screen is off.")
            },
            confirmButton = {
                TextButton(onClick = {
                    showNotificationRationale = false
                    pendingPermissionRequest  = true
                }) {
                    Text("Allow", color = MaterialTheme.colorScheme.primary, fontWeight = FontWeight.Bold)
                }
            },
            dismissButton = {
                TextButton(onClick = { showNotificationRationale = false }) {
                    Text("Not Now", color = Color.Gray)
                }
            }
        )
    }
    if (isSessionComplete) {
        val sheetState = rememberModalBottomSheetState(skipPartiallyExpanded = true)
        ModalBottomSheet(
            onDismissRequest = {  },
            sheetState       = sheetState,
            containerColor   = Color(0xFF1C1C1E),
            dragHandle         = { BottomSheetDefaults.DragHandle(color = Color.Gray) }
        ) {
            SessionSummarySheet(
                completedSets = completedCount,
                totalSets     = totalCount,
                onFinish      = {
                    viewModel.finishSession(onComplete = onNavigateBack)
                }
            )
        }
    }
    Scaffold(
        containerColor = BackgroundColor,
        topBar = {
            SessionTopBar(
                onBack = onNavigateBack,
                sessionName = (sessionState as? Resource.Success)?.data?.name ?: "Loading..."
            )
        }
    ) { padding ->
        Box(
            modifier = Modifier
                .fillMaxSize()
                .padding(padding)
        ) {
            when (val res = sessionState) {
                is Resource.Loading -> {
                    CircularProgressIndicator(
                        modifier = Modifier.align(Alignment.Center),
                        color = MaterialTheme.colorScheme.primary
                    )
                }
                is Resource.Error -> {
                    Text(
                        text = res.message ?: "Error",
                        color = MaterialTheme.colorScheme.error,
                        modifier = Modifier.align(Alignment.Center)
                    )
                }
                is Resource.Success -> {
                    val session = res.data
                    if (session == null) {
                        Text(
                            text = "No session found for today",
                            color = Color.Gray,
                            modifier = Modifier.align(Alignment.Center)
                        )
                    } else {
                        SessionContent(session, viewModel)
                    }
                }
            }
        }
    }
}
@Composable
private fun SessionTopBar(onBack: () -> Unit, sessionName: String) {
    Row(
        modifier = Modifier
            .fillMaxWidth()
            .statusBarsPadding()
            .padding(horizontal = 16.dp, vertical = 8.dp),
        verticalAlignment = Alignment.CenterVertically
    ) {
        IconButton(onClick = onBack) {
            Icon(Icons.AutoMirrored.Filled.ArrowBack, contentDescription = "Back", tint = Color.White)
        }
        Text(
            text = sessionName,
            style = MaterialTheme.typography.titleLarge,
            fontWeight = FontWeight.Bold,
            color = Color.White,
            modifier = Modifier.padding(start = 8.dp)
        )
    }
}
@OptIn(ExperimentalAnimationApi::class, ExperimentalFoundationApi::class)
@Composable
private fun SessionContent(session: TrainingSession, viewModel: SessionPlayerViewModel) {
    LazyColumn(
        modifier = Modifier.fillMaxSize(),
        contentPadding = PaddingValues(16.dp),
        verticalArrangement = Arrangement.spacedBy(24.dp)
    ) {
        items(session.blocks) { block ->
            BlockItem(block, viewModel)
        }
    }
}
@OptIn(ExperimentalAnimationApi::class, ExperimentalFoundationApi::class)
@Composable
private fun BlockItem(block: ExerciseBlock, viewModel: SessionPlayerViewModel) {
    Column {
        Row(verticalAlignment = Alignment.CenterVertically) {
            Text(
                text = block.type.name.uppercase(),
                style = MaterialTheme.typography.labelLarge,
                color = MaterialTheme.colorScheme.primary,
                fontWeight = FontWeight.Bold,
                letterSpacing = 1.sp
            )
            if (block.sets > 1) {
                Spacer(modifier = Modifier.width(8.dp))
                Text(
                    text = "${block.sets} ROUNDS",
                    style = MaterialTheme.typography.labelSmall,
                    color = Color.Gray
                )
            }
        }
        Spacer(modifier = Modifier.height(12.dp))
        Card(
            shape = RoundedCornerShape(24.dp),
            colors = CardDefaults.cardColors(containerColor = Color(0xFF1C1C1E))
        ) {
            Column(modifier = Modifier.padding(16.dp)) {
                block.exercises.forEachIndexed { index, exercise ->
                    ExerciseItem(exercise, viewModel)
                    if (index < block.exercises.size - 1) {
                        HorizontalDivider(
                            modifier = Modifier.padding(vertical = 16.dp),
                            color = Color.DarkGray.copy(alpha = 0.5f)
                        )
                    }
                }
            }
        }
    }
}
@OptIn(ExperimentalAnimationApi::class, ExperimentalFoundationApi::class)
@Composable
private fun ExerciseItem(exercise: Exercise, viewModel: SessionPlayerViewModel) {
    Column {
        Text(
            text = exercise.name,
            style = MaterialTheme.typography.titleMedium,
            fontWeight = FontWeight.Bold,
            color = Color.White
        )
        if (!exercise.notes.isNullOrBlank()) {
            Spacer(modifier = Modifier.height(4.dp))
            Row(verticalAlignment = Alignment.CenterVertically) {
                Icon(Icons.Default.Info, contentDescription = null, modifier = Modifier.size(12.dp), tint = Color.Gray)
                Spacer(modifier = Modifier.width(4.dp))
                Text(exercise.notes, style = MaterialTheme.typography.bodySmall, color = Color.Gray)
            }
        }
        Spacer(modifier = Modifier.height(12.dp))
        exercise.sets.forEachIndexed { index, set ->
            Row(
                modifier = Modifier
                    .fillMaxWidth()
                    .padding(vertical = 4.dp),
                horizontalArrangement = Arrangement.SpaceBetween,
                verticalAlignment = Alignment.CenterVertically
            ) {
                Text(
                    text = "SET ${index + 1}",
                    style = MaterialTheme.typography.labelMedium,
                    color = Color.Gray,
                    modifier = Modifier.width(40.dp)
                )
                Column(modifier = Modifier.weight(1f)) {
                    Text(
                        text = "${set.reps} Reps",
                        style = MaterialTheme.typography.bodyMedium,
                        color = Color.White,
                        fontWeight = FontWeight.Medium
                    )
                }
                val weightText = viewModel.calculateWeight(exercise.name, set.intensity, set.intensityType)
                Column(horizontalAlignment = Alignment.End) {
                    Text(
                        text = if (set.intensityType == IntensityType.PERCENTAGE_1RM) {
                            "${set.intensity.toInt()}% 1RM"
                        } else {
                            "${set.intensity.toInt()} ${set.intensityType.name}"
                        },
                        style = MaterialTheme.typography.bodySmall,
                        color = MaterialTheme.colorScheme.primary
                    )
                    if (weightText.isNotEmpty()) {
                        Text(
                            text = weightText,
                            style = MaterialTheme.typography.bodyLarge,
                            fontWeight = FontWeight.ExtraBold,
                            color = Color.White
                        )
                    }
                }
                if (set.restSeconds > 0) {
                    Spacer(modifier = Modifier.width(16.dp))
                    Row(verticalAlignment = Alignment.CenterVertically) {
                        Icon(Icons.Default.Timer, contentDescription = null, modifier = Modifier.size(14.dp), tint = Color.Gray)
                        Spacer(modifier = Modifier.width(4.dp))
                        Text("${set.restSeconds}s", style = MaterialTheme.typography.bodySmall, color = Color.Gray)
                    }
                }
            }
        }
    }
}
@Composable
private fun SessionSummarySheet(
    completedSets: Int,
    totalSets: Int,
    onFinish: () -> Unit
) {
    Column(
        modifier = Modifier
            .fillMaxWidth()
            .padding(24.dp),
        horizontalAlignment = Alignment.CenterHorizontally
    ) {
        Icon(
            Icons.Default.CheckCircle,
            contentDescription = null,
            tint = MaterialTheme.colorScheme.primary,
            modifier = Modifier.size(64.dp)
        )
        Spacer(modifier = Modifier.height(16.dp))
        Text(
            "Session Complete!",
            style = MaterialTheme.typography.headlineMedium,
            fontWeight = FontWeight.Black,
            color = Color.White
        )
        Text(
            "Another day closer to reaching your peak.",
            style = MaterialTheme.typography.bodyMedium,
            color = Color.Gray
        )
        Spacer(modifier = Modifier.height(32.dp))
        Row(
            modifier = Modifier.fillMaxWidth(),
            horizontalArrangement = Arrangement.SpaceEvenly
        ) {
            StatItem(label = "Sets Done", value = "$completedSets/$totalSets")
            StatItem(
                label = "Completion",
                value = if (totalSets > 0) "${(completedSets * 100 / totalSets)}%" else "—"
            )
        }
        Spacer(modifier = Modifier.height(32.dp))
        Button(
            onClick  = onFinish,
            modifier = Modifier.fillMaxWidth().height(56.dp),
            shape    = RoundedCornerShape(16.dp),
            colors   = ButtonDefaults.buttonColors(
                containerColor = MaterialTheme.colorScheme.primary
            )
        ) {
            Text(
                "Finish Session",
                fontWeight = FontWeight.ExtraBold,
                style      = MaterialTheme.typography.titleMedium
            )
        }
    }
}
@Composable
private fun StatItem(label: String, value: String) {
    Column(horizontalAlignment = Alignment.CenterHorizontally) {
        Text(
            text       = value,
            style      = MaterialTheme.typography.headlineSmall,
            fontWeight = FontWeight.Bold,
            color      = Color.White
        )
        Text(
            text  = label,
            style = MaterialTheme.typography.labelMedium,
            color = Color.Gray
        )
    }
}



package com.gcancino.levelingup.presentation.player.session
import android.annotation.SuppressLint
import android.app.Application
import android.content.ComponentName
import android.content.Context
import android.content.Intent
import android.content.ServiceConnection
import android.os.Build
import android.os.IBinder
import android.os.VibrationEffect
import android.os.Vibrator
import android.os.VibratorManager
import android.util.Log
import androidx.compose.animation.ExperimentalAnimationApi
import androidx.compose.foundation.ExperimentalFoundationApi
import androidx.lifecycle.AndroidViewModel
import androidx.lifecycle.SavedStateHandle
import androidx.lifecycle.viewModelScope
import com.gcancino.levelingup.core.Resource
import com.gcancino.levelingup.domain.models.exercise.*
import com.gcancino.levelingup.domain.repositories.ExerciseRepository
import com.gcancino.levelingup.domain.repositories.PlayerRepository
import dagger.hilt.android.lifecycle.HiltViewModel
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.ExperimentalCoroutinesApi
import kotlinx.coroutines.Job
import kotlinx.coroutines.flow.*
import kotlinx.coroutines.launch
import timber.log.Timber
import java.util.Date
import java.util.Locale
import javax.inject.Inject
import androidx.core.content.edit
import com.google.firebase.auth.FirebaseAuth
@ExperimentalAnimationApi
@ExperimentalFoundationApi
@HiltViewModel
class SessionPlayerViewModel @Inject constructor(
    application: Application,
    private val exerciseRepository: ExerciseRepository,
    private val playerRepository: PlayerRepository,
    private val auth: FirebaseAuth,
    savedStateHandle: SavedStateHandle
) : AndroidViewModel(application) {
    private val TAG = "SessionPlayerViewModel"
    private val dateTimestamp: Long = savedStateHandle.get("date") ?: System.currentTimeMillis()
    private val _session = MutableStateFlow<Resource>(Resource.Loading())
    val session: StateFlow<Resource> = _session.asStateFlow()
    private val _oneRepMaxes = MutableStateFlow<Resource<List>>(Resource.Loading())
    val oneRepMaxes: StateFlow<Resource<List>> = _oneRepMaxes.asStateFlow()
    private val _completedSets = MutableStateFlow<Map<String, Set>>(emptyMap())
    val completedSets: StateFlow<Map<String, Set>> = _completedSets.asStateFlow()
    val completedSetsCount: StateFlow = _completedSets
        .map { map -> map.values.sumOf { it.size } }
        .stateIn(viewModelScope, SharingStarted.Eagerly, 0)
    val totalSetsCount: StateFlow = _session
        .map { resource ->
            (resource as? Resource.Success)?.data
                ?.blocks
                ?.sumOf { block -> block.exercises.sumOf { it.sets.size } }
                ?: 0
        }
        .stateIn(viewModelScope, SharingStarted.Eagerly, 0)
    val isSessionComplete: StateFlow = combine(
        completedSetsCount,
        totalSetsCount
    ) { completed, total ->
        total in 1..completed
    }.stateIn(viewModelScope, SharingStarted.Eagerly, false)
    private val _restTimeRemaining = MutableStateFlow(0)
    val restTimeRemaining: StateFlow = _restTimeRemaining.asStateFlow()
    private val _restTotalSeconds = MutableStateFlow(0)
    val restTotalSeconds: StateFlow = _restTotalSeconds.asStateFlow()
    @SuppressLint("StaticFieldLeak")
    private var timerService: TimerService? = null
    private var timerCollectJob: Job? = null
    private val serviceConnection = object : ServiceConnection {
        override fun onServiceConnected(name: ComponentName?, binder: IBinder?) {
            Timber.tag(TAG).d("TimerService connected")
            val service = (binder as TimerService.TimerBinder).getService()
            timerService = service
            timerCollectJob = viewModelScope.launch {
                launch { service.timerValue.collect { _restTimeRemaining.value = it } }
                launch { service.totalSeconds.collect { _restTotalSeconds.value = it } }
            }
        }
        override fun onServiceDisconnected(name: ComponentName?) {
            Timber.tag(TAG).d("TimerService disconnected")
            timerService = null
            timerCollectJob?.cancel()
        }
    }
    private val prefs = getApplication()
        .getSharedPreferences("session_player_prefs", Context.MODE_PRIVATE)
    private val _hasRequestedPermission = MutableStateFlow(
        prefs.getBoolean("notification_permission_requested", false)
    )
    val hasRequestedPermission: StateFlow = _hasRequestedPermission.asStateFlow()
    fun markPermissionRequested() {
        _hasRequestedPermission.value = true
        prefs.edit { putBoolean("notification_permission_requested", true) }
    }
    private val _plateCalculatorTarget = MutableStateFlow(null)
    val plateCalculatorTarget: StateFlow = _plateCalculatorTarget.asStateFlow()
    init {
        bindTimerService()
        loadSession()
        loadOneRepMaxes()
        restoreCompletedSets()
    }
    private fun bindTimerService() {
        val intent = Intent(getApplication(), TimerService::class.java)
        getApplication().bindService(intent, serviceConnection, Context.BIND_AUTO_CREATE)
        Timber.tag(TAG).d("Binding to TimerService")
    }
    private fun loadSession() {
        viewModelScope.launch(Dispatchers.IO) {
            exerciseRepository.getSessionForDate(Date(dateTimestamp))
                .collect { res ->
                    _session.value = res
                    if (res is Resource.Success && res.data != null) {
                        exerciseRepository.saveTodaySessionLocally(res.data)
                    }
                }
        }
    }
    private fun loadOneRepMaxes() {
        viewModelScope.launch(Dispatchers.IO) {
            exerciseRepository.getOneRepMaxes()
                .collect { res ->
                    _oneRepMaxes.value = res
                }
        }
    }
    @OptIn(ExperimentalCoroutinesApi::class)
    private fun restoreCompletedSets() {
        viewModelScope.launch(Dispatchers.IO) {
            _session
                .filterIsInstance<Resource.Success>()
                .mapNotNull { it.data?.id }
                .distinctUntilChanged()
                .flatMapLatest { sessionId ->
                    exerciseRepository.getLogsForSessionAsMap(sessionId)
                }
                .collect { restoredMap ->
                    if (_completedSets.value.isEmpty()) {
                        _completedSets.value = restoredMap
                    }
                }
        }
    }
    private fun triggerHaptic() {
        val context = getApplication()
        try {
            if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.S) {
                val manager = context.getSystemService(VibratorManager::class.java)
                val vibrator = manager?.defaultVibrator
                vibrator?.vibrate(
                    VibrationEffect.createOneShot(40, VibrationEffect.DEFAULT_AMPLITUDE)
                )
            } else if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
                @Suppress("DEPRECATION")
                val vibrator = context.getSystemService(Context.VIBRATOR_SERVICE) as? Vibrator
                vibrator?.vibrate(
                    VibrationEffect.createOneShot(40, VibrationEffect.DEFAULT_AMPLITUDE)
                )
            } else {
                @Suppress("DEPRECATION")
                val vibrator = context.getSystemService(Context.VIBRATOR_SERVICE) as? Vibrator
                @Suppress("DEPRECATION")
                vibrator?.vibrate(40)
            }
        } catch (e: Exception) {
            Timber.tag(TAG).w("Haptic feedback failed: ${e.message}")
        }
    }
    fun toggleSetCompleted(
        sessionId: String,
        exerciseId: String,
        setIndex: Int,
        block: ExerciseBlock,
        setRestSeconds: Int
    ) {
        triggerHaptic()
        val currentMap  = _completedSets.value.toMutableMap()
        val currentSets = currentMap[exerciseId]?.toMutableSet() ?: mutableSetOf()
        val isMarkingCompleted = !currentSets.contains(setIndex)
        viewModelScope.launch(Dispatchers.IO) {
            if (isMarkingCompleted) {
                currentSets.add(setIndex)
                exerciseRepository.toggleSetLog(sessionId, exerciseId, setIndex, true)
                val restToUse = if (block.type == BlockType.Main) {
                    setRestSeconds
                } else {
                    val isLast = block.exercises.lastOrNull()?.id == exerciseId
                    if (isLast) block.restAfterBlock else block.restBetweenExercises
                }
                if (restToUse > 0) {
                    TimerService.startService(getApplication(), restToUse)
                }
            } else {
                currentSets.remove(setIndex)
                exerciseRepository.toggleSetLog(sessionId, exerciseId, setIndex, false)
                TimerService.stopService(getApplication())
            }
            currentMap[exerciseId] = currentSets
            _completedSets.value = currentMap
        }
    }
    fun skipRest() {
        timerService?.stopTimer() ?: TimerService.stopService(getApplication())
        _restTimeRemaining.value = 0
        _restTotalSeconds.value  = 0
    }
    private fun findOneRepMaxForExercise(exerciseName: String): OneRepMax? {
        val orms = (_oneRepMaxes.value as? Resource.Success)?.data ?: return null
        val normalizedName = exerciseName.replace(" ", "").lowercase(Locale.ROOT)
        var orm = orms.find {
            it.exerciseName.replace(" ", "").lowercase(Locale.ROOT) == normalizedName
        }
        if (orm == null) {
            orm = orms.filter {
                val n = it.exerciseName.replace(" ", "").lowercase(Locale.ROOT)
                normalizedName.contains(n) || n.contains(normalizedName)
            }.maxByOrNull { it.exerciseName.length }
        }
        return orm
    }
    fun calculateWeight(exerciseName: String, intensity: Double, intensityType: IntensityType): String {
        if (intensityType != IntensityType.PERCENTAGE_1RM) return ""
        val orm = findOneRepMaxForExercise(exerciseName) ?: return "Set 1RM"
        val weight = (orm.weight * intensity) / 100.0
        return "${String.format(Locale.US, "%.1f", weight)} kg"
    }
    fun calculateWeightKg(exerciseName: String, intensity: Double, intensityType: IntensityType): Double? {
        if (intensityType != IntensityType.PERCENTAGE_1RM) return null
        val orm = findOneRepMaxForExercise(exerciseName)
        return orm?.let { (it.weight * intensity) / 100.0 }
    }
    fun openPlateCalculator(targetKg: Double) {
        _plateCalculatorTarget.value = targetKg
    }
    fun finishSession(onComplete: () -> Unit) {
        val uid = auth.currentUser?.uid ?: return
        val xpToAward = completedSetsCount.value * 10
        viewModelScope.launch(Dispatchers.IO) {
            playerRepository.awardXP(uid, xpToAward)
            onComplete()
        }
    }
    fun closePlateCalculator() {
        _plateCalculatorTarget.value = null
    }
    fun calculatePlates(targetKg: Double): List<Pair> {
        val barWeight   = 20.0
        val plateSizes  = listOf(25.0, 20.0, 15.0, 10.0, 5.0, 2.5, 1.25)
        val weightPerSide = (targetKg - barWeight) / 2.0
        if (weightPerSide <= 0) return emptyList()
        var remaining = weightPerSide
        val result    = mutableListOf<Pair>()
        for (plate in plateSizes) {
            val count = (remaining / plate).toInt()
            if (count > 0) {
                result.add(Pair(plate, count))
                remaining -= plate * count
                remaining  = Math.round(remaining * 1000.0) / 1000.0
            }
        }
        return result
    }
    override fun onCleared() {
        super.onCleared()
        timerCollectJob?.cancel()
        try {
            getApplication().unbindService(serviceConnection)
        } catch (e: IllegalArgumentException) { }
    }
}



package com.gcancino.levelingup.presentation.player.session
import android.app.*
import android.content.Context
import android.content.Intent
import android.content.pm.ServiceInfo
import android.os.Binder
import android.os.Build
import android.os.IBinder
import androidx.core.app.NotificationCompat
import com.gcancino.levelingup.MainActivity
import kotlinx.coroutines.*
import kotlinx.coroutines.flow.MutableStateFlow
import androidx.compose.material3.ExperimentalMaterial3Api
import android.util.Log
import androidx.annotation.RequiresApi
import androidx.compose.animation.ExperimentalAnimationApi
import androidx.compose.foundation.ExperimentalFoundationApi
import timber.log.Timber
@ExperimentalAnimationApi
@ExperimentalFoundationApi
class TimerService : Service() {
    private val serviceScope = CoroutineScope(Dispatchers.Default + SupervisorJob())
    private var timerJob: Job? = null
    inner class TimerBinder : Binder() {
        fun getService(): TimerService = this@TimerService
    }
    private val binder = TimerBinder()
    val timerValue = MutableStateFlow(0)
    val totalSeconds = MutableStateFlow(0)
    companion object {
        const val CHANNEL_ID = "timer_channel"
        const val NOTIFICATION_ID = 1
        const val FINISHED_NOTIFICATION_ID = 2
        const val EXTRA_SECONDS = "SECONDS"
        fun startService(context: Context, seconds: Int) {
            Timber.tag("TimerService").d("startService() → $seconds seconds")
            val intent = Intent(context, TimerService::class.java).apply {
                putExtra(EXTRA_SECONDS, seconds)
            }
            context.startForegroundService(intent)
        }
        fun stopService(context: Context) {
            Timber.tag("TimerService").d("stopService()")
            context.stopService(Intent(context, TimerService::class.java))
        }
    }
    override fun onBind(intent: Intent?): IBinder = binder
    override fun onStartCommand(intent: Intent?, flags: Int, startId: Int): Int {
        val seconds = intent?.getIntExtra(EXTRA_SECONDS, 0) ?: 0
        Timber.tag("TimerService").d("onStartCommand() → $seconds seconds")
        createNotificationChannel()
        try {
            startForeground(NOTIFICATION_ID, createNotification(seconds))
        } catch (e: Exception) {
            Timber.tag("TimerService").e(e, "Error starting foreground service")
        }
        startTimer(seconds)
        return START_NOT_STICKY
    }
    fun startTimer(seconds: Int) {
        timerJob?.cancel()
        totalSeconds.value = seconds
        timerValue.value = seconds
        Timber.tag("TimerService").d("Timer started → $seconds seconds")
        timerJob = serviceScope.launch {
            while (timerValue.value > 0) {
                delay(1000)
                timerValue.value -= 1
                updateNotification(timerValue.value)
            }
            Timber.tag("TimerService").d("Timer finished")
            showTimerFinishedNotification()
            stopForeground(STOP_FOREGROUND_REMOVE)
            stopSelf()
        }
    }
    fun stopTimer() {
        timerJob?.cancel()
        timerValue.value = 0
        totalSeconds.value = 0
        Timber.tag("TimerService").d("Timer stopped manually")
        stopForeground(STOP_FOREGROUND_REMOVE)
        stopSelf()
    }
    private fun updateNotification(seconds: Int) {
        val notificationManager = getSystemService(Context.NOTIFICATION_SERVICE) as NotificationManager
        notificationManager.notify(NOTIFICATION_ID, createNotification(seconds))
    }
    private fun createNotification(seconds: Int): Notification {
        val intent = Intent(this, MainActivity::class.java).apply {
            flags = Intent.FLAG_ACTIVITY_SINGLE_TOP
        }
        val pendingIntent = PendingIntent.getActivity(
            this, 0, intent,
            PendingIntent.FLAG_IMMUTABLE or PendingIntent.FLAG_UPDATE_CURRENT
        )
        val builder = NotificationCompat.Builder(this, CHANNEL_ID)
            .setContentTitle("Leveling Up Rest Timer")
            .setContentText("Next set in ${seconds}s")
            .setSmallIcon(android.R.drawable.ic_dialog_info)
            .setOngoing(true)
            .setOnlyAlertOnce(true)
            .setContentIntent(pendingIntent)
            .setPriority(NotificationCompat.PRIORITY_MAX)
            .setCategory(NotificationCompat.CATEGORY_ALARM)
            .setVisibility(NotificationCompat.VISIBILITY_PUBLIC)
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.S) {
            builder.setForegroundServiceBehavior(Notification.FOREGROUND_SERVICE_IMMEDIATE)
        }
        return builder.build()
    }
    private fun showTimerFinishedNotification() {
        val intent = Intent(this, MainActivity::class.java).apply {
            flags = Intent.FLAG_ACTIVITY_SINGLE_TOP
        }
        val pendingIntent = PendingIntent.getActivity(
            this, 0, intent,
            PendingIntent.FLAG_IMMUTABLE or PendingIntent.FLAG_UPDATE_CURRENT
        )
        val notification = NotificationCompat.Builder(this, CHANNEL_ID)
            .setContentTitle("Rest Finished!")
            .setContentText("Time is over. Start your next set!")
            .setSmallIcon(android.R.drawable.ic_dialog_info)
            .setPriority(NotificationCompat.PRIORITY_HIGH)
            .setCategory(NotificationCompat.CATEGORY_ALARM)
            .setVisibility(NotificationCompat.VISIBILITY_PUBLIC)
            .setAutoCancel(true)
            .setContentIntent(pendingIntent)
            .setDefaults(Notification.DEFAULT_ALL)
            .build()
        val notificationManager = getSystemService(Context.NOTIFICATION_SERVICE) as NotificationManager
        notificationManager.notify(FINISHED_NOTIFICATION_ID, notification)
    }
    private fun createNotificationChannel() {
        val channel = NotificationChannel(
            CHANNEL_ID,
            "Workout Timer",
            NotificationManager.IMPORTANCE_HIGH
        ).apply {
            description = "Shows the remaining rest time during your workout"
            lockscreenVisibility = Notification.VISIBILITY_PUBLIC
            enableVibration(true)
            enableLights(true)
        }
        val manager = getSystemService(NotificationManager::class.java)
        manager?.createNotificationChannel(channel)
    }
    override fun onDestroy() {
        Timber.tag("TimerService").d("onDestroy()")
        timerJob?.cancel()
        serviceScope.cancel()
        timerValue.value = 0
        totalSeconds.value = 0
        super.onDestroy()
    }
}



