import com.kizitonwose.calendar.core.WeekDay
import com.kizitonwose.calendar.core.daysOfWeek
import java.time.DayOfWeek
import java.time.LocalDate
@Composable
fun WeeklyCalendar(
    viewModel: CalendarViewmodel
) {
    val selectedDate by viewModel.selectedDate.collectAsState()
    val today = LocalDate.now()
    val state = rememberWeekCalendarState(
        startDate = viewModel.startMonth.atDay(1),
        endDate = viewModel.endMonth.atEndOfMonth(),
        firstVisibleWeekDate = today,
        firstDayOfWeek = viewModel.firstDayOfWeek
    )
    Card(
        modifier = Modifier
            .fillMaxWidth(),
        shape = RoundedCornerShape(24.dp),
        colors = CardDefaults.cardColors(
            containerColor = Color(0xFF1A1A1A)
        )
    ) {
        Column(
            modifier = Modifier.padding(20.dp)
        ) {
            WeekHeader(viewModel.firstDayOfWeek)
            Spacer(modifier = Modifier.height(16.dp))
            WeekCalendar(
                modifier = Modifier.fillMaxWidth(),
                state = state,
                dayContent = { day ->
                    DayCell(
                        day = day,
                        isSelected = day.date == selectedDate,
                        isToday = day.date == today,
                        onClick = {
                            viewModel.onSelectedDate(day.date)
                        }
                    )
                }
            )
        }
    }
}
@Composable
fun WeekHeader(firstDayOfWeek: DayOfWeek) {
    val days = daysOfWeek(firstDayOfWeek)
    Row(
        modifier = Modifier.fillMaxWidth()
    ) {
        days.forEach { day ->
            Box(
                modifier = Modifier
                    .weight(1f),
                contentAlignment = Alignment.Center
            ) {
                Text(
                    text = day.name.take(3),
                    color = Color.Gray,
                    letterSpacing = 2.sp,
                    fontWeight = FontWeight.Medium,
                    fontSize = 12.sp
                )
            }
        }
    }
}
@Composable
fun DayCell(
    day: WeekDay,
    isSelected: Boolean,
    isToday: Boolean,
    onClick: () -> Unit
) {
    Column(
        modifier = Modifier
            .fillMaxWidth(),
        horizontalAlignment = Alignment.CenterHorizontally
    ) {
        Box(
            modifier = Modifier
                .size(40.dp)
                .background(
                    if (isSelected) Color(0xFF3A3A3A)
                    else Color.Transparent,
                    CircleShape
                )
                .clickable { onClick() },
            contentAlignment = Alignment.Center
        ) {
            Text(
                text = day.date.dayOfMonth.toString(),
                color = Color.White
            )
        }
        Spacer(modifier = Modifier.height(6.dp))
        if (isSelected) {
            Box(
                modifier = Modifier
                    .width(18.dp)
                    .height(4.dp)
                    .background(
                        Color(0xFF3A7AFE),
                        RoundedCornerShape(2.dp)
                    )
            )
        } else {
            Spacer(modifier = Modifier.height(4.dp))
        }
    }
}



